 6", "caption": "大浦柱狀節理海岸 — photo 6"}, {"id": 7, "type": "photo", "src": "/images/tours/jusangjeolli/kakaotalk-20260510-230028438-13.webp", "location": "大浦柱狀節理海岸", "alt": "大浦柱狀節理海岸 — gallery image 7", "caption": "大浦柱狀節理海岸 — photo 7"}, {"id": 8, "type": "photo", "src": "/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-15.webp", "location": "正房瀑布", "alt": "正房瀑布 — gallery image 8", "caption": "正房瀑布 — photo 8"}, {"id": 9, "type": "photo", "src": "/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-16.webp", "location": "正房瀑布", "alt": "正房瀑布 — gallery image 9", "caption": "正房瀑布 — photo 9"}, {"id": 10, "type": "photo", "src": "/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-17.webp", "location": "正房瀑布", "alt": "正房瀑布 — gallery image 10", "caption": "正房瀑布 — photo 10"}, {"id": 11, "type": "photo", "src": "/images/tours/jeju-haenyeo-museum/haenyeo-sunset-diving-ai.webp", "location": "城山海女自由潛水表演", "alt": "城山海女自由潛水表演 — gallery image 11", "caption": "城山海女自由潛水表演 — photo 11"}, {"id": 12, "type": "photo", "src": "/images/tours/seongsan-ilchulbong/kakaotalk-20260510-230028438-06.webp", "location": "城山日出峰", "alt": "城山日出峰 — gallery image 12", "caption": "城山日出峰 — photo 12"}, {"id": 13, "type": "photo", "src": "/images/tours/seongsan-ilchulbong/kakaotalk-20260510-230028438-07.webp", "location": "城山日出峰", "alt": "城山日出峰 — gallery image 13", "caption": "城山日出峰 — photo 13"}, {"id": 14, "type": "photo", "src": "/images/tours/seongsan-ilchulbong/kakaotalk-20260510-230028438-08.webp", "location": "城山日出峰", "alt": "城山日出峰 — gallery image 14", "caption": "城山日出峰 — photo 14"}, {"id": 15, "type": "photo", "src": "/images/tours/seongsan-ilchulbong/kakaotalk-20260510-230028438-09.webp", "location": "城山日出峰", "alt": "城山日出峰 — gallery image 15", "caption": "城山日出峰 — photo 15"}, {"id": 16, "type": "photo", "src": "/images/tours/ilchulland/chatgpt-image-2026-5-8-07-45-52.webp", "location": "萬丈窟熔岩洞", "alt": "萬丈窟熔岩洞 — gallery image 16", "caption": "萬丈窟熔岩洞 — photo 16"}], "itineraryStops": [{"number": 1, "time": "08:45", "duration": "45 分鐘", "name": "漢拿山 1100 高地濕地（拉姆薩爾公約 + 聯合國教科文組織）", "category": "高山濕地——拉姆薩爾濕地 + 位於漢拿山聯合國教科文組織世界遺產範圍內", "description": "**漢拿山 1100 高地濕地（한라산 1100고지 습지）**是位於漢拿山高原上的高海拔高山濕地系統，坐落於連接濟州市與西歸浦中文的**韓國最高國道——1100 號公路**沿線，**海拔恰好 1,100 公尺**。該地被列為**拉姆薩爾國際重要濕地（編號第 1893 號，2009 年 10 月 12 日指定）**，同時位於**漢拿山聯合國教科文組織世界遺產（2007 年）**、**濟州島聯合國教科文組織生物圈保護區（2002 年）**及**漢拿山國立公園（1970 年）**範圍之內——使此地成為全球少數擁有**四重國際／國家級重疊認定**的地點之一。\n\n濕地由**16 處以上不相連的淡水沼澤與水池**組成，分布於低坡度高原地帶，匯聚並蓄留雨水，形成**小型永久性湖泊與泥炭沼澤**，孕育多樣植物群落，並有大量濟州特有物種。已記錄的生物多樣性包括**韓國境內 3 種受威脅鳥類及 1 種受威脅植物**，以及多種濟州島特有哺乳類、爬蟲類與昆蟲。該地於**2008 年接待遊客 900,000 人次**（漢拿山遊客中心數據）。\n\n遊覽體驗：設有**1 公里長的木棧道環形步道**，配備觀景台、解說牌及入口處的小型自然歷史展覽。**秋季紅葉（10 至 11 月）**與**冬季雪景（12 至 2 月）**為最受歡迎的拍攝季節；**春季與夏季**則可觀賞濕地植物及特有物種。**免費入場**；鄰近的**1100 休息站（1100 휴게소）**提供室內廁所、咖啡館及小型紀念品店。**對當地社群的文化與宗教意義**已記載於拉姆薩爾登錄文件中——與山水神靈相關的歷史薩滿朝聖活動。", "image": "/images/tours/hallasan-1100/kakaotalk-20260510-230009595-21.webp", "highlights": ["**拉姆薩爾濕地第 1893 號**（2009 年 10 月 12 日指定）——國際重要濕地", "**海拔 1,100 公尺**——位於韓國**最高國道**（1100 號公路）上", "**四重國際認定**——拉姆薩爾公約 + 聯合國教科文組織世界遺產 + 生物圈保護區 + 國立公園", "**16 處以上不相連濕地**——淡水沼澤 + 水池 + 泥炭沼澤", "**3 種受威脅鳥類 + 1 種受威脅植物**；多種濟州特有物種", "**900,000 人次遊客（2008 年）**——由漢拿山遊客中心管理", "**1公里木棧道環形步道**，設有觀景台及解說標誌牌", "**秋季紅葉＋冬季雪景** = 招牌拍攝季節", "**免費入場**；鄰近1100休息站（室內洗手間＋咖啡廳）"], "timeUsed": ["遊覽車抵達及停車於1100休息站 — 約5分鐘", "木棧道環形步道＋觀景台 — 約25分鐘", "解說標誌牌＋自然史展示 — 約10分鐘", "緩衝時間／咖啡廳洗手間 — 約5分鐘"], "whyOnRoute": "1100 高地是漢拏山唯一一處無需預約、也無需數小時登頂健行，便能融入全島環線的站點。於韓國最高公路上的一段短程高山木棧道，在漫長南下車程展開之前，於漢拏山的聯合國教科文組織世界遺產區域內揭開這一天的序幕。", "_poi_meta": {"poi_key": "hallasan_1100_wetland", "kb_version": "1.20", "verified_date": "2026-04-29", "sources": ["Ramsar Sites Information Service — 1100 Altitude Wetland (Site No. 1893)", "UNESCO Man and the Biosphere Programme — Jeju Island Biosphere Reserve", "Korea National Park Service — Hallasan National Park 1100 Wetland records", "Mt Halla Visitor Centre — visitor management documentation", "Jeju Special Self-Governing Province — Wetland Protected Area designation 2009"]}, "visitBasics": {"hours": "全天開放（木棧道）；遊客中心09:00–18:00", "closed": "1100公路可能於大雪期間暫時封閉（12月至2月）", "admission": "免費", "walking": "輕鬆 — 1公里木棧道；地勢平坦，無障礙通行"}, "convenience": {"restroom": "於遊客中心取得", "parking": "遊客中心提供免費停車"}, "smartNotes": {"photo": "通往濕地的木棧道及遠方漢拿山景為標誌性拍攝畫面；秋季（10月）草地呈現金黃色彩", "facilities": "遊客中心提供點心及旅遊資訊", "tip": "請備妥保暖衣物——氣溫比沿海濟州低5至10°C；冬季請確認路況；下山往南可結合天帝淵瀑布同遊"}, "images": ["/images/tours/hallasan-1100/kakaotalk-20260510-230009595-21.webp", "/images/tours/hallasan-1100/kakaotalk-20260510-230009595-22.webp", "/images/tours/hallasan-1100/kakaotalk-20260510-230009595-23.webp"], "imageCredits": [{"url": "/images/tours/hallasan-1100/kakaotalk-20260510-230009595-21.webp", "source": "atoc-korea"}, {"url": "/images/tours/hallasan-1100/kakaotalk-20260510-230009595-22.webp", "source": "atoc-korea"}, {"url": "/images/tours/hallasan-1100/kakaotalk-20260510-230009595-23.webp", "source": "atoc-korea"}], "galleryItems": [{"id": 1, "type": "photo", "src": "/images/tours/hallasan-1100/kakaotalk-20260510-230009595-21.webp", "location": "漢拿山 1100 高地濕地（拉姆薩爾公約 + 聯合國教科文組織）", "caption": "漢拿山 1100 高地濕地（拉姆薩爾公約 + 聯合國教科文組織） — photo 1", "alt": "漢拿山 1100 高地濕地（拉姆薩爾公約 + 聯合國教科文組織） — gallery image 1"}, {"id": 2, "type": "photo", "src": "/images/tours/hallasan-1100/kakaotalk-20260510-230009595-22.webp", "location": "漢拿山 1100 高地濕地（拉姆薩爾公約 + 聯合國教科文組織）", "caption": "漢拿山 1100 高地濕地（拉姆薩爾公約 + 聯合國教科文組織） — photo 2", "alt": "漢拿山 1100 高地濕地（拉姆薩爾公約 + 聯合國教科文組織） — gallery image 2"}, {"id": 3, "type": "photo", "src": "/images/tours/hallasan-1100/kakaotalk-20260510-230009595-23.webp", "location": "漢拿山 1100 高地濕地（拉姆薩爾公約 + 聯合國教科文組織）", "caption": "漢拿山 1100 高地濕地（拉姆薩爾公約 + 聯合國教科文組織） — photo 3", "alt": "漢拿山 1100 高地濕地（拉姆薩爾公約 + 聯合國教科文組織） — gallery image 3"}]}, {"number": 2, "time": "10:00", "duration": "45 分鐘", "name": "大浦柱狀節理海岸", "category": "火山海岸線——六角柱狀節理熔岩", "description": "**大浦柱狀節理（대포 주상절리，別稱「지삿개」）** 是位於中文（Jungmun）海岸的一段 **1 公里長的六角柱狀節理玄武岩懸崖**，於 **2005年1月6日被指定為天然紀念物第443號**。岩柱從海面拔地而起，高達 **30至40公尺**，緊密排列成 **5至7邊形多邊體**（以六邊形為主）——此一幾何形態源於**漢拏山側翼噴發（約25萬至14萬年前）的玄武岩熔岩流入海洋後，在冷卻收縮過程中垂直於冷卻面龜裂**所形成。\n\n全球著名的柱狀節理地形包括**英國巨人堤道（Giant''s Causeway）**、**美國惡魔柱（Devils Postpile）**及**蘇格蘭芬格爾洞（Fingal''s Cave）**——大浦柱狀節理是**東亞最具代表性的範例**，也是最易抵達的一處。長達800公尺的**木棧道環形步道**引領遊客直抵岩柱正上方的欄杆邊緣；**大潮之日，海浪拍打岩柱，水花可飛濺高達20公尺**，偶爾越過護欄。\n\n門票：**成人₩2,000 / 青少年₩1,000 / 7歲以下及65歲以上免費**。此景點隸屬**濟州世界地質公園（UNESCO，2010年10月認定）**，是全島 **13處官方地質遺址**之一，與城山日出峰、萬丈窟熔岩洞及水月峰齊名。懸崖頂部觀景台為**無障礙設施**（輪椅及嬰兒車可通行）。環形步道沿途設有三處觀景平台，可從不同角度欣賞岩柱：**第一平台**可側面觀賞岩柱（最適合拍攝六邊形幾何構圖），**中段平台**可俯視岩柱頂部紋路，而**遠端平台**則可在晴天以漢拏山為背景，將長達1公里的海岸線盡收眼底。\n\n**最佳攝影時段：14:00至16:00**，此時西斜陽光正面照射岩柱面；傍晚造訪雖可拍出剪影構圖，但會失去岩柱紋理細節。開放時間：**09:00至18:00（最後入場17:30）**，全年開放。", "image": "/images/tours/jusangjeolli/chatgpt-image-2026-2-15-10-01-04.webp", "highlights": ["**天然紀念物第443號** — 指定日期 **2005年1月6日**，為濟州最新指定的海岸天然紀念物", "岩柱高達 **30至40公尺**，沿 **1公里**海岸線緊密排列成 **5至7邊形多邊體**（以六邊形為主）", "形成原因：**約25萬至14萬年前漢拏山側翼熔岩流入海洋冷卻**，垂直於冷卻面收縮龜裂", "**東亞最具代表性的柱狀節理地形** — 可與巨人堤道、惡魔柱、芬格爾洞媲美", "**大潮之日水花可噴達20公尺** — 海浪噴泉攝影時機", "**0.8公里木棧道環形步道**，步行約15分鐘 — 無障礙設施，輪椅及嬰兒車可通行", "隸屬**濟州世界地質公園（UNESCO，2010年10月）** — 全島共13處地質遺址", "門票 **成人₩2,000 / 青少年₩1,000 / 7歲以下及65歲以上免費**", "晴天可見漢拏山山頂於北方，在地質上屬**熔岩流向的直接下游**"], "timeUsed": ["停車＋購票＋入場 — 約5分鐘", "步行至第一觀景台 — 約5分鐘", "懸崖邊岩柱觀賞＋拍照 — 約15分鐘", "繼續木棧道環形步道 — 約10分鐘", "返回巴士 — 約10分鐘"], "whyOnRoute": "柱狀節理是濟州火山地質最有效率的單一呈現——南海岸上的一個短暫停留，於漢拏山高地與正房瀑布之間的途中，以視覺凝練了熔岩遇海的故事。", "_poi_meta": {"poi_key": "daepo_jusangjeolli_cliff", "kb_version": "1.18", "verified_date": "2026-04-29", "sources": ["Cultural Heritage Administration — Natural Monument No. 443 designation (2005-01-06)", "Jeju Global Geopark official site (geopark.jeju.go.kr)", "UNESCO Global Geoparks Network — Jeju (2010 designation)", "VisitJeju — Daepo Jusangjeolli", "Korea Geological Survey — Jeju basalt formation studies"]}, "visitBasics": {"hours": "09:00–18:00（最後入場17:40）", "closed": "全年開放", "admission": "成人₩2,000 / 兒童及青少年₩1,000", "walking": "輕鬆至中等"}, "convenience": {"restroom": "入口區域", "parking": "可停車（收費停車場）"}, "smartNotes": {"photo": "浪向、水花與側光瞬息萬變，廣角海岸構圖在此尤為出色。", "facilities": "入口區域設施完善，觀景步道本身相對簡單易行。", "tip": "即使在晴天，海岸通常也比濟州內陸更為寒冷多風。"}, "images": ["/images/tours/jusangjeolli/chatgpt-image-2026-2-15-10-01-04.webp", "/images/tours/jusangjeolli/kakaotalk-20260510-230028438-11.webp", "/images/tours/jusangjeolli/kakaotalk-20260510-230028438-12.webp", "/images/tours/jusangjeolli/kakaotalk-20260510-230028438-13.webp", "/images/tours/jusangjeolli/photo-005.webp"], "imageCredits": [{"url": "/images/tours/jusangjeolli/chatgpt-image-2026-2-15-10-01-04.webp", "source": "atoc-korea"}, {"url": "/images/tours/jusangjeolli/kakaotalk-20260510-230028438-11.webp", "source": "atoc-korea"}, {"url": "/images/tours/jusangjeolli/kakaotalk-20260510-230028438-12.webp", "source": "atoc-korea"}, {"url": "/images/tours/jusangjeolli/kakaotalk-20260510-230028438-13.webp", "source": "atoc-korea"}, {"url": "/images/tours/jusangjeolli/photo-005.webp", "source": "atoc-korea"}], "galleryItems": [{"id": 1, "type": "photo", "src": "/images/tours/jusangjeolli/chatgpt-image-2026-2-15-10-01-04.webp", "location": "大浦柱狀節理海岸", "caption": "大浦柱狀節理海岸 — photo 1", "alt": "大浦柱狀節理海岸 — gallery image 1"}, {"id": 2, "type": "photo", "src": "/images/tours/jusangjeolli/kakaotalk-20260510-230028438-11.webp", "location": "大浦柱狀節理海岸", "caption": "大浦柱狀節理海岸 — photo 2", "alt": "大浦柱狀節理海岸 — gallery image 2"}, {"id": 3, "type": "photo", "src": "/images/tours/jusangjeolli/kakaotalk-20260510-230028438-12.webp", "location": "大浦柱狀節理海岸", "caption": "大浦柱狀節理海岸 — photo 3", "alt": "大浦柱狀節理海岸 — gallery image 3"}, {"id": 4, "type": "photo", "src": "/images/tours/jusangjeolli/kakaotalk-20260510-230028438-13.webp", "location": "大浦柱狀節理海岸", "caption": "大浦柱狀節理海岸 — photo 4", "alt": "大浦柱狀節理海岸 — gallery image 4"}, {"id": 5, "type": "photo", "src": "/images/tours/jusangjeolli/photo-005.webp", "location": "大浦柱狀節理海岸", "caption": "大浦柱狀節理海岸 — photo 5", "alt": "大浦柱狀節理海岸 — gallery image 5"}]}, {"number": 3, "time": "11:05", "duration": "60分鐘", "name": "正房瀑布", "category": "海岸瀑布 — 直接落入大海（亞洲唯一）", "description": "**正房瀑布（정방폭포，「直落入海之瀑」）**是**亞洲唯一直接落入大海的瀑布** — 從玄武岩懸崖**垂直落下23公尺**直入太平洋，無中間水潭，無河床出口。瀑布**寬8公尺**，底部水潭深5公尺，每逢潮汐便與外海相通。這一獨特的地理特徵，使正房瀑布躋身**「瀛洲十景（영주십경，濟州十大勝景）」**之列 — 此為朝鮮時代文人所定，記錄島上最具詩意景觀的典範名錄。\n\n瀛洲十景由**18世紀儒學學者李源祚（이원조）**整理成冊，其中亦涵蓋城山日出、漢拿山頂及天帝淵 — 意味著今日的環線行程在一日之內即涵蓋**十景中的3景**。瀑布旁的崖壁上刻有銘文**「徐市過此（서불과차，徐市西歸）」**，相傳為**徐福（서복）**所留 — 他是傳說中秦朝方士，受**秦始皇（約西元前219年）**之命出海尋訪長生不老仙藥。\n\n民間傳說他歸途中曾途經此地 — 這段銘文即是地名**「西歸浦（서귀포，「徐市西歸之地」）」**的語源所在。入口處需沿**130級石階**下行至海灣（坡度較陡，建議穿著護膝舒適鞋款）。門票：**成人₩2,000 ／ 青少年₩1,000 ／ 7歲以下及65歲以上免費**。瀑布底部水霧瀰漫、氣候涼爽，是著名的夏日消暑勝地。\n\n**當地海女（해녀，女性潛水採集者 — 聯合國教科文組織2016年非物質文化遺產）**於風平浪靜之日，有時會直接在海灣販售新鮮海膽、鮑魚與海螺 — 這是在正式博物館場域以外，難得一見的記錄潛水社群真實生活的攝影機會。", "image": "/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-15.webp", "highlights": ["**亞洲唯一直接落入大海的瀑布** — 垂直落差23公尺，無河床", "瀑布**寬8公尺**，底部水潭深5公尺，每逢潮汐便沖入太平洋", "**「瀛洲十景」**之一 — 朝鮮時代濟州十大勝景", "**「徐市過此」石刻** — 相傳為徐福（秦朝方士，約西元前219年）所題，為地名「西歸浦」之由來", "通往海灣須走 **130級石階** — 建議穿著護膝舒適鞋履", "門票 **成人₩2,000 / 青少年₩1,000 / 7歲以下及65歲以上免費**", "瀑布底部水霧形成涼爽微氣候 — 夏日天然消暑勝地", "風平浪靜時，當地**海女（해녀，女性潛水人）**有時會在海灣販售新鮮漁獲", "攝影「黃金時段」通常為 **14:00–14:30**，此時西照陽光正面照亮瀑布"], "timeUsed": ["入口 + 購票 + 下行（130級台階） — 約10分鐘", "海灣觀景台 + 瀑布拍攝 — 約25分鐘", "可選崖邊步道 + 徐市過此石刻 — 約10分鐘", "返回遊覽車上行 — 約10分鐘", "緩衝時間 — 約5分鐘"], "whyOnRoute": "正房瀑布——亞洲唯一直接落入大海的瀑布——距西歸浦的午餐街區僅數分鐘，因此恰好銜接在午間休息之前，毫無折返。", "_poi_meta": {"poi_key": "jeongbang_falls", "kb_version": "1.18", "verified_date": "2026-04-29", "sources": ["Korea Cultural Heritage Foundation — Yeongjusipgyeong canon", "VisitJeju — Jeongbang Pokpo official listing", "Seogwipo City tourism office — admission and access", "Korea Geological Survey — coastal waterfall inventory", "Jeju Folklore Records — Xu Fu / Seobulgwacha inscription study"]}, "visitBasics": {"hours": "09:00–17:20", "closed": "全年開放", "admission": "成人 2,000韓元 / 兒童 1,000韓元", "walking": "中等難度，含樓梯"}, "convenience": {"restroom": "入口區域", "parking": "提供停車場"}, "smartNotes": {"photo": "下方礁岩區適合拍攝富有氛圍感的照片，但地面濕滑加上海浪飛沫，實際體驗可能比預期更為費力。", "facilities": "基本設施位於入口附近。", "tip": "由於需走樓梯及礁石路，實際體驗通常比地圖上看起來更耗費體力。"}, "images": ["/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-15.webp", "/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-16.webp", "/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-17.webp"], "imageCredits": [{"url": "/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-15.webp", "source": "atoc-korea"}, {"url": "/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-16.webp", "source": "atoc-korea"}, {"url": "/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-17.webp", "source": "atoc-korea"}], "galleryItems": [{"id": 1, "type": "photo", "src": "/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-15.webp", "location": "正房瀑布", "caption": "正房瀑布 — photo 1", "alt": "正房瀑布 — gallery image 1"}, {"id": 2, "type": "photo", "src": "/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-16.webp", "location": "正房瀑布", "caption": "正房瀑布 — photo 2", "alt": "正房瀑布 — gallery image 2"}, {"id": 3, "type": "photo", "src": "/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-17.webp", "location": "正房瀑布", "caption": "正房瀑布 — photo 3", "alt": "正房瀑布 — gallery image 3"}]}, {"number": 4, "time": "12:15", "duration": "60 分鐘", "name": "午餐 — 西歸浦在地料理", "category": "午間休整 — 西歸浦在地料理", "description": "**西歸浦（서귀포）市中心60分鐘休整** — 濟州南部城市，以**西歸浦每日偶來市場（서귀포매일올레시장）**的新鮮海產及鮑魚豐饒的海岸聞名。依季節與團體人數採預設輪替菜單：旺季（9月至2月）漁船靠岸時，於西歸浦專門店享用**갈치조림（白帶魚燉辣醬）**；全年皆可於市場鄰近餐廳享用**전복비빔밥（鮑魚拌飯）**；或為偏好燒烤的旅客提供**흑돼지구이（濟州黑豬烤肉）**。\n\n黑豬（***Sus scrofa* domesticus，濟州黑豬品種**）於**2015年被指定為文化財料第5號**，至今仍為濟州受保護品種。素食替代選項可依需求提供：附時令蔬菜的**비빔국수（涼拌辣拌麵）**。午餐地點**距正房瀑布步行僅5分鐘** — 餐後有意小憩的旅客，可在繼續徒步前於市場茶飲／咖啡廳排稍作停留。", "image": null, "highlights": ["**西歸浦**市中心 — 濟州南部漁業與海鮮之都", "旺季（9月至2月）供應**갈치조림（白帶魚燉辣醬）**，全年供應**전복비빔밥（鮑魚拌飯）**", "**흑돼지（濟州黑豬）**選項 — 文化財料第5號（2015年）", "可依需求提供**素食비빔국수（涼拌辣拌麵）**替代選項", "午餐地點**距正房瀑布入口步行僅5分鐘** — 無需大巴接駁", "接送時收集團體飲食需求；菜單事先確認"], "timeUsed": ["步行至午餐地點 — 約5分鐘", "點餐＋用餐＋飲品 — 約45分鐘", "步行至正房瀑布入口 — 約5分鐘", "緩衝時間 — 約5分鐘"], "whyOnRoute": "午餐安排於西歸浦市中心，位處南海岸景點與漫長東行車程之間，讓團體恢復精力，迎接下午的攀登與洞穴行程。", "visitBasics": {"hours": "視餐廳營業時間而定", "closed": "依場地而異", "admission": "除非另有說明，餐費於現場支付", "walking": "極少"}, "convenience": {"restroom": "餐廳內部", "parking": "提供停車位"}, "smartNotes": {"photo": "由於當日大部分行程以自然景觀為主，餐點照片有助於豐富路線的視覺節奏。", "facilities": "用餐相關設施通常相當完善。", "tip": "在此從容用餐，勝於匆忙進食而耗損下午的體力。"}, "images": []}, {"time": "14:00", "duration": "45 分鐘", "name": "城山海女自由潛水表演", "category": "聯合國教科文組織非物質遺產——女性潛水人現場表演", "description": "濟州的海女（女性潛水人）獲列為聯合國教科文組織人類非物質文化遺產（2016 年）。在城山日出峰南側的海灣，許多年屆 60 至 80 歲的資深潛水人，每日進行自由潛水示範，通常約於 13:30 與 15:00 各一場。她們以傳統勞動歌謠揭開序幕，接著在不使用任何呼吸裝備的情況下下潛 5–10 公尺，採集海螺、海膽與鮑魚，並在長時間下潛後浮出水面，發出標誌性的「숨비소리（sumbi-sori）」呼吸哨音以吐氣換息。表演結束後，潛水人會將新鮮漁獲切成生魚片，就在水邊販售。這是與一支正逐漸消逝、延續 400 年的母系潛水文化難得的活生生相遇——隨著現存潛水人日漸年邁，這份文化正慢慢凋零。示範於露天進行、取決於海象；遇取消之日，路線將改為參觀鄰近下道里的海女博物館，於室內透過潛水裝備、歷史與影片訴說同一段故事。", "image": "/images/tours/jeju-haenyeo-museum/haenyeo-sunset-diving-ai.webp", "highlights": ["聯合國教科文組織非物質文化遺產（2016 年）——濟州的女性潛水人", "城山海灣的現場自由潛水示範（約 13:30 / 15:00）", "傳統潛水歌謠與標誌性的「숨비소리」呼吸聲", "取消替代方案：室內的海女博物館訴說同一段故事"], "timeUsed": ["步行下行至海女海灣——約5分鐘", "自由潛水示範＋潛水歌謠——約25分鐘", "水邊的新鮮漁獲／生魚片——約10分鐘", "返回車輛——約5分鐘"], "whyOnRoute": "海女表演為一天的火山地形添上人文、文化的層次——而由於它就位於城山腳下，於攀登之前無需任何額外車程。", "_poi_meta": {"poi_key": "jeju_haenyeo_museum", "kb_version": "1.29", "verified_date": "2026-06-23", "sources": ["VisitKorea", "UNESCO ICH 2016", "Jeju Haenyeo Museum"]}, "smartNotes": {"photo": "潛水人身著防寒衣入水的畫面，以及之後鋪展於礁岩上的新鮮漁獲", "facilities": "潛水人的攤位販售剛潛水捕撈的新鮮海膽、海螺與鮑魚生魚片", "tip": "表演時間隨海象與季節而變動——導遊將於當日確認。若取消，您將改為參觀海女博物館。"}, "convenience": {"restroom": "城山日出峰入口廣場設有廁所", "parking": "與城山日出峰停車場共用"}, "visitBasics": {"hours": "露天示範通常約於 13:30 與 15:00 進行（視季節與天候而定）", "closed": "大浪或惡劣天氣時取消；海女博物館週一休館", "admission": "觀賞示範免費；海女博物館（替代方案）成人約 ₩1,100", "walking": "極少——一段平緩的短程步道下行至海灣"}, "images": ["/images/tours/jeju-haenyeo-museum/haenyeo-sunset-diving-ai.webp"], "imageCredits": [{"url": "/images/tours/jeju-haenyeo-museum/haenyeo-sunset-diving-ai.webp", "source": "atoc-korea"}], "galleryItems": [], "number": 5}, {"number": 6, "time": "14:55", "duration": "90分鐘", "name": "城山日出峰", "category": "聯合國教科文組織認定凝灰岩錐 — 日出峰（三重UNESCO認定）", "description": "**城山日出峰（성산일출봉，「日出峰」）** 是一座**形成於5,000年前的蘇特西式水火山凝灰岩錐** — 這一罕見地貌由海底玄武岩噴發衝破海面時形成，岩漿與海水相遇，產生蒸汽爆炸式噴發，堆積出**182公尺高的要塞形火山口**邊緣，而非典型的熔岩錐。其成果正是聯合國教科文組織正式稱之為**「蘇特西式火山地體出露的傑出典範」**。火山口**寬600公尺、深90公尺**，周圍環繞**99塊嶙峋岩石**，當地傳說將其比喻為石冠。\n\n城山日出峰擁有**三重UNESCO認定**：**世界自然遺產（2007年7月2日列入）**，為**「濟州火山島與熔岩管」遺產地**的一部分；**生物圈保護區（2002年）**；以及**全球地質公園（2010年10月）** — 在韓國景點中，僅漢拏山本身可與此相提並論。**18座日本帝國二戰時期洞窟**（1945年神風特攻隊自殺艇掩體）鑿入面海的基部。步道：**單程0.8公里，爬升約140公尺，寬闊石階步道來回60分鐘**。\n\n**海女（해녀）表演**每日於錐體下方礁岩灣**14:00**各舉行一場 — 濟州女性潛水人（2016年UNESCO非物質文化遺產）不使用水肺裝備下潛。門票**2025年4月更新**：**成人₩5,000 / 青少年及兒童₩2,500 / 團體成人₩1,600**，7歲以下及65歲以上免費。山頂觀景台亦列入**瀛洲十景（濟州十大勝景）**之列，並持續是韓國首屈一指的**年度新年日出朝聖地** — 每年1月1日黎明前逾5萬名遊客登頂，自1995年起更設有官方日出慶典活動。\n\n**牛島（우도，「牛之島」）** — 韓國最大的次生火山島 — 在山頂清晰可見，位於離岸4公里處，可從城山港搭乘**15分鐘渡輪**前往（來回票₩10,500），適合在其他行程中有額外時間的旅客。", "image": "/images/tours/seongsan-ilchulbong/kakaotalk-20260510-230028438-06.webp", "highlights": ["**三重UNESCO認定**：世界自然遺產 2007-07-02 + 生物圈保護區 2002 + 全球地質公園 2010-10", "**形成於5,000年前** — 蘇特西式水火山噴發，岩漿與海水相遇，蒸汽爆炸孕育而生", "火山口**寬600公尺 × 深90公尺**，環繞**99塊嶙峋岩石**（「石冠」）", "**海拔182公尺** — 單程0.8公里 / 爬升約140公尺，石階步道來回60分鐘", "基部**18座日本帝國二戰時期洞窟** — 1945年神風特攻隊自殺艇掩體", "**海女表演每日 14:00** 於海邊小灣舉行 — 2016年聯合國教科文組織非物質文化遺產", "**2025年4月更新票價**：成人 ₩5,000 / 青少年 ₩2,500 / 7歲以下及65歲以上免費", "春秋開放時間 **05:00–19:00**（最後入場時間 18:20）", "**每月第一個星期一休館**（不定期休息日）"], "timeUsed": ["停車 + 購票 + 園區簡介 — 約10分鐘", "登上山頂觀景台（0.8公里 / 爬升140公尺）— 約30分鐘", "山頂景觀 + 火山口邊緣拍照 — 約20分鐘", "下山 — 約20分鐘", "可選擇在山腳欣賞海女表演（每日1場，下午2點；惡劣天氣時可能取消）— 約10分鐘"], "whyOnRoute": "城山日出峰是這一天的招牌攀登——一座三重聯合國教科文組織認定的凝灰岩錐，就緊鄰海女海灣，因此團體可先觀賞潛水人表演，再行攀登，無需額外車程。", "_poi_meta": {"poi_key": "seongsan_ilchulbong", "kb_version": "1.18", "verified_date": "2026-04-29", "sources": ["UNESCO WHC inscription 1264 (Jeju Volcanic Island and Lava Tubes, 2007-07-02)", "UNESCO Global Geoparks Network — Jeju (2010-10 designation)", "Cultural Heritage Administration — Natural Monument designation 2000-07-19", "Seongsan Ilchulbong official site (seongsan.kr) — April 2025 admission update", "Jeju Haenyeo Museum — UNESCO Intangible 2016 inscription record"]}, "visitBasics": {"hours": "收費開放時間可能因季節而異", "closed": "每月第一個星期一休館（若適逢公眾假期，則順延至次日）", "admission": "成人 5,000韓元 / 兒童 2,500韓元", "walking": "若選擇登頂，體力需求為中等至中等偏高"}, "convenience": {"restroom": "山腳區域及周邊設施", "parking": "提供大型停車場"}, "smartNotes": {"photo": "比起只拍攝山頂，將火山口與海岸線同時納入畫面的寬闊構圖，通常更令人滿意。", "facilities": "山腳區域設施完善。", "tip": "人潮、天氣及團體體能狀況，皆可能影響登頂體驗的難度與滿足感。"}, "images": ["/images/tours/seongsan-ilchulbong/kakaotalk-20260510-230028438-06.webp", "/images/tours/seongsan-ilchulbong/kakaotalk-20260510-230028438-07.webp", "/images/tours/seongsan-ilchulbong/kakaotalk-20260510-230028438-08.webp", "/images/tours/seongsan-ilchulbong/kakaotalk-20260510-230028438-09.webp", "/images/tours/seongsan-ilchulbong/kakaotalk-20260510-230028438-10.webp", "/images/tours/seongsan-ilchulbong/photo-006.webp", "/images/tours/seongsan-ilchulbong/seongsan-haenyeo-show-ai.webp"], "imageCredits": [{"url": "/images/tours/seongsan-ilchulbong/kakaotalk-20260510-230028438-06.webp", "source": "atoc-korea"}, {"url": "/images/tours/seongsan-ilchulbong/kakaotalk-20260510-230028438-07.webp", "source": "atoc-korea"}, {"url": "/images/tours/seongsan-ilchulbong/kakaotalk-20260510-230028438-08.webp", "source": "atoc-korea"}, {"url": "/images/tours/seongsan-ilchulbong/kakaotalk-20260510-230028438-09.webp", "source": "atoc-korea"}, {"url": "/images/tours/seongsan-ilchulbong/kakaotalk-20260510-230028438-10.webp", "source": "atoc-korea"}, {"url": "/images/tours/seongsan-ilchulbong/photo-006.webp", "source": "atoc-korea"}, {"url": "/images/tours/seongsan-ilchulbong/seongsan-haenyeo-show-ai.webp", "source": "atoc-korea"}, {"url": "/images/tours/seongsan-ilchulbong/photo-006.webp", "source": "atoc-korea"}], "galleryItems": [{"id": 1, "type": "photo", "src": "/images/tours/seongsan-ilchulbong/kakaotalk-20260510-230028438-06.webp", "location": "城山日出峰", "caption": "城山日出峰 — photo 1", "alt": "城山日出峰 — gallery image 1"}, {"id": 2, "type": "photo", "src": "/images/tours/seongsan-ilchulbong/kakaotalk-20260510-230028438-07.webp", "location": "城山日出峰", "caption": "城山日出峰 — photo 2", "alt": "城山日出峰 — gallery image 2"}, {"id": 3, "type": "photo", "src": "/images/tours/seongsan-ilchulbong/kakaotalk-20260510-230028438-08.webp", "location": "城山日出峰", "caption": "城山日出峰 — photo 3", "alt": "城山日出峰 — gallery image 3"}, {"id": 4, "type": "photo", "src": "/images/tours/seongsan-ilchulbong/kakaotalk-20260510-230028438-09.webp", "location": "城山日出峰", "caption": "城山日出峰 — photo 4", "alt": "城山日出峰 — gallery image 4"}, {"id": 5, "type": "photo", "src": "/images/tours/seongsan-ilchulbong/kakaotalk-20260510-230028438-10.webp", "location": "城山日出峰", "caption": "城山日出峰 — photo 5", "alt": "城山日出峰 — gallery image 5"}, {"id": 6, "type": "photo", "src": "/images/tours/seongsan-ilchulbong/photo-006.webp", "location": "城山日出峰", "caption": "城山日出峰 — photo 6", "alt": "城山日出峰 — gallery image 6"}, {"id": 7, "type": "photo", "src": "/images/tours/seongsan-ilchulbong/seongsan-haenyeo-show-ai.webp", "location": "城山日出峰", "caption": "城山日出峰 — photo 12", "alt": "城山日出峰 — gallery image 12"}], "liveStatusWidget": "haenyeo"}, {"time": "16:55", "duration": "50 分鐘", "name": "萬丈窟熔岩洞", "category": "聯合國教科文組織熔岩洞——世界自然遺產洞穴壓軸", "description": "萬丈窟是世界上最精彩的熔岩洞之一，也是濟州聯合國教科文組織登錄的核心洞穴。它約形成於 10 萬至 30 萬年前，當時來自拒文岳火山系統的熔岩流向大海，留下一條長約 7.4 公里的隧道。其中 1 公里路段開放遊客參觀，終點為一根 7.6 公尺高的熔岩石柱——地球上已知最高的熔岩石柱——由上層通道傾瀉而下的熔岩所形成。沿途洞穴展示了教科書級的火山特徵：熔岩鐘乳石、條紋狀爬覆於洞壁的熔岩流線、地面繩狀的繩熔岩、洞穴珊瑚，以及一塊巧合之下酷似濟州島輪廓的「熔岩龜」岩石。它屬於 2007 年登錄的「濟州火山島與熔岩洞」聯合國教科文組織世界遺產。洞內全年維持約 11–21°C 的穩定溫度，因此夏季涼爽、冬季溫和——雨天時更是天然的遮蔽所。地面崎嶇、潮濕且昏暗，公眾步行段來回約 1 公里，需時 30–45 分鐘。萬丈窟會不定期因保育與容量管制而封閉；遇此情況，路線將改為參觀鄰近、同樣出自此一系統的日出樂園美千洞熔岩洞。", "image": "/images/tours/ilchulland/chatgpt-image-2026-5-8-07-45-52.webp", "highlights": ["屬於聯合國教科文組織「濟州火山島與熔岩洞」世界遺產（2007 年）", "終點為世界已知最高的熔岩石柱——約 7.6 公尺", "於 7.4 公里熔岩洞系統內開放 1 公里步行段", "全年涼爽 11–21°C——這一天的天然避雨防暑之所"], "timeUsed": ["抵達＋於萬丈窟停車——約5分鐘", "步行進入至 7.6 公尺熔岩石柱——約20分鐘", "熔岩石柱＋折返步行——約20分鐘", "入口處緩衝／如廁——約5分鐘"], "whyOnRoute": "萬丈窟以第三處聯合國教科文組織自然遺產，為這條環線畫下句點，也是當日唯一有遮蔽的室內站點。它距城山約 30 分鐘，正位於返回濟州市的途中，因此能在不增加路程的情況下收束整條環線。", "_poi_meta": {"poi_key": "manjanggul_lava_tube", "kb_version": "1.29", "verified_date": "2026-06-23", "sources": ["UNESCO World Heritage 2007", "Jeju World Natural Heritage Center", "VisitKorea"]}, "smartNotes": {"photo": "步道盡頭的 7.6 公尺熔岩石柱，以及形似濟州島輪廓的「熔岩龜」岩石", "facilities": "入口處設有咖啡廳、廁所與小型商店；拒文岳熔岩洞系統就在附近", "tip": "請攜帶一件輕便外套——洞穴全年涼爽——並穿著防滑鞋款以應對潮濕、崎嶇的地面。封閉之日，行程將改為參觀日出樂園美千洞熔岩洞。"}, "convenience": {"restroom": "入口廣場設有廁所", "parking": "入口處設有免費停車場"}, "visitBasics": {"hours": "每日 09:00–18:00（最後入場約 17:10）", "closed": "每月第一個星期三；不定期保育封閉", "admission": "成人 ₩4,000 ／ 青少年 ₩2,000；7 歲以下及 65 歲以上免費", "walking": "中等——來回約 1 公里，行走於崎嶇、潮濕、昏暗的洞穴地面，部分路段天花板低矮"}, "images": ["/images/tours/ilchulland/chatgpt-image-2026-5-8-07-45-52.webp"], "imageCredits": [{"url": "/images/tours/ilchulland/chatgpt-image-2026-5-8-07-45-52.webp", "source": "atoc-korea"}], "galleryItems": [], "number": 7}], "routeFlowStops": [{"name": "漢拏山 1100", "theme": "高地", "type": "01"}, {"name": "柱狀節理", "theme": "海崖", "type": "02"}, {"name": "正房", "theme": "瀑布", "type": "03"}, {"name": "午餐", "theme": "休整", "type": "04"}, {"name": "海女表演", "theme": "文化", "type": "05"}, {"name": "城山", "theme": "火山口", "type": "06"}, {"name": "萬丈窟", "theme": "熔岩洞", "type": "07"}], "routePhases": [{"phase": "上午——山岳與南海岸", "duration": "1-3", "description": ""}, {"phase": "中午——午餐與海女文化", "duration": "4-5", "description": ""}, {"phase": "壓軸——火山口與熔岩洞", "duration": "6-7", "description": ""}], "routeShapeIntro": {"title": "行程脈絡", "subtitle": "這一天從漢拏山 1100 高地出發，途經南海岸的海崖與瀑布，午餐後向東橫越，欣賞現場海女自由潛水表演、登上城山日出峰，並探訪萬丈窟熔岩洞。全程約 180 公里、總計約 5 小時車程；接送通常為 08:30–09:00，返回濟州市約在 18:00–18:30。"}, "whyTourWorks": {"bestFor": ["在濟州只有一天行程的旅客", "希望遊覽全島聯合國教科文組織遺址的初次造訪者", "想同時體驗標誌性地標與在地文化的旅客", "喜歡積極、整日觀光的旅客"], "routeLogicSections": [{"title": "為一日盡覽濟州精華而設計", "icon": "clock-3", "iconBg": "bg-amber-50/80", "items": [{"label": "從漢拏山高地揭開序幕", "detail": "以 1,100 公尺的高山濕地作為起點，在展開漫長的跨島車程之前，先讓整日旅程映襯著濟州的山岳核心。"}, {"label": "將南海岸置於行程中段", "detail": "柱狀節理、正房瀑布與午餐串起由西向東的流暢推進，並讓視覺密度在午間維持飽滿。"}, {"label": "以東部的火山口與熔岩洞收尾", "detail": "海女文化、城山攀登與萬丈窟熔岩洞，讓東段行程成為強而有力的聯合國教科文組織壓軸，而非各自分散的零星景點。"}]}, {"title": "為何這一天格外充實", "icon": "mountain", "iconBg": "bg-sky-50/80", "items": [{"label": "三處聯合國教科文組織世界遺產", "detail": "漢拏山、城山日出峰與萬丈窟皆屬濟州聯合國教科文組織登錄範圍——是單一濟州日程中所能達到的最高遺址密度。"}, {"label": "一層活生生的文化體驗", "detail": "海女自由潛水表演，為一個原本以火山地形為主軸的日子，添上聯合國教科文組織非物質文化遺產的人文層次。"}, {"label": "時間效益最大化", "detail": "山岳、海崖、瀑布、文化、火山口與熔岩洞於一條環線之內——精心設計，讓僅僅一天仍宛如一趟完整的濟州之旅。"}]}, {"title": "當現場狀況有所變動時", "icon": "wind", "iconBg": "bg-slate-50/80", "items": [{"label": "海女表演視天候而定", "detail": "露天的自由潛水示範在大浪時可能取消；遇此情況，路線將改為參觀海女博物館。"}, {"label": "萬丈窟有不定期封閉", "detail": "若熔岩洞因保育或容量管制而封閉，將以鄰近的日出樂園美千洞熔岩洞作為替代景點。"}, {"label": "返程時間可能略有變動", "detail": "交通狀況、團體步行速度與現場人潮，皆可能對最終返程時間造成些微變動。"}]}], "lessIdealFor": ["偏好悠閒、輕鬆步調的旅客", "希望避免爬樓梯或上坡步行的旅客", "攜帶極年幼孩童同行的團體", "在陰涼、昏暗洞穴通道中會感到不適的旅客"]}, "practicalAccordionItems": [{"id": "pickup", "title": "接送與返回時間", "preview": "早出發，傍晚返回濟州市", "content": ["上午 08:30 至 09:00 於濟州市接載", "約 18:00–18:30 返回濟州市", "可視情況安排機場接送", "最終集合時間於前一晚確認"]}, {"id": "walking", "title": "步行與地形", "preview": "活動量大的路線，含樓梯、攀登與洞穴", "content": ["漢拏山 1100 濕地是一段輕鬆的 1 公里木棧道環形步道。", "正房瀑布包含樓梯及岩石步道。", "若團體選擇登頂，城山日出峰為階梯攀登。", "萬丈窟來回約 1 公里，行走於崎嶇、潮濕、昏暗的洞穴地面。", "強烈建議穿著防滑效果佳的舒適鞋款。"]}, {"id": "weather", "title": "天候與封閉調整", "preview": "通常按計劃進行，並備有替代方案", "content": ["小雨：行程通常照常進行——洞穴本身即為天然遮蔽", "大浪：海女自由潛水表演可能改為參觀海女博物館", "萬丈窟封閉：改以鄰近的日出樂園美千洞熔岩洞替代", "冬季：漢拏山 1100 高地可能積雪或結冰——路線可能調整停留時間"]}, {"id": "flight", "title": "若您當天抵達或離開濟州", "preview": "您需要保留充裕的傍晚緩衝時間", "content": ["這是一條高密度路線，於一天之內遊覽濟州的代表性精華景點。", "當天抵達或離境均可行，但前提是您要保留足夠的傍晚緩衝時間。", "強烈建議搭乘晚班航班。", "判斷時間風險時，請將交通狀況、步行速度及現場實際情形納入考量。"]}, {"id": "wear", "title": "穿著與攜帶建議", "preview": "步行鞋、多層次穿搭，以及應對洞穴的輕便外套", "content": ["防滑效果佳的步行鞋", "適應山區、海岸與洞穴溫差的多層次服裝", "一件輕便外套——萬丈窟全年涼爽", "帽子及防曬用品", "隨身水瓶"]}, {"id": "included", "title": "包含／不包含項目", "preview": "含導覽、車輛、接送及所有門票", "variant": "included", "content": ["專業英語導遊", "小團體專車", "濟州市區飯店接送", "所有景點門票（漢拏山 1100、柱狀節理、正房、城山、萬丈窟／替代日改為海女博物館）", "瓶裝水", "午餐（現場自費）", "個人購物費用", "導遊小費"]}], "practicalWeatherStatic": {"today": {"temp": "—", "label": "即時天氣整合"}, "tomorrow": {"temp": "—", "label": "每日更新"}, "_seasonalSummary": "A full-island loop covering east, south, and west Jeju in one day. Weather can vary between regions — coastal stops mild year-round, but inland transit can be cooler and windier.", "_seasonalTemperatures": [{"season": "Spring (Mar–May)", "range": "8–22°C", "notes": "Cherry blossoms on east coast in early April; mild driving conditions."}, {"season": "Summer (Jun–Aug)", "range": "22–30°C", "notes": "Hot but humidity moderated by coastal driving. Cheonjiyeon falls at peak flow."}, {"season": "Autumn (Sep–Nov)", "range": "10–24°C", "notes": "Best season — clearest visibility across all stops, comfortable walking temps."}, {"season": "Winter (Dec–Feb)", "range": "3–10°C", "notes": "Wind chill significant at Seongsan rim and Jusangjeolli cliffs. Fewer crowds at all stops."}]}, "seasonalVariations": [{"season": "春季", "description": "山間空氣格外清新，全島能見度通常更佳，視野也更加明亮清晰。"}, {"season": "夏季", "description": "白晝最長，海岸線的色彩往往顯得最為鮮豔飽滿。"}, {"season": "秋季", "description": "晴朗的天空常讓環島路線從頭到尾都令人格外心曠神怡。"}, {"season": "冬季", "description": "空氣變得更加清冽透澈，山海之間的對比也愈發鮮明。"}], "bookingTrustItems": [{"icon": "clock-3", "title": "一日盡覽濟州精華", "description": "三處聯合國教科文組織遺址加上海女文化", "iconBg": "bg-emerald-50/80", "body": "持牌在地營運商專為時間僅有一天、又想遍覽濟州最具辨識度地標的旅客而設計這條環線——漢拏山高地、柱狀節理海崖、直落入海的瀑布、現場海女表演、城山凝灰岩錐與萬丈窟熔岩洞，盡在一條環線之中。"}, {"icon": "mountain", "title": "聚焦於標誌性地標", "description": "從漢拏山高地一路延伸至聯合國教科文組織熔岩洞", "iconBg": "bg-sky-50/80", "body": "定期經營全島環線的路線專家——景點順序的安排將折返路程降至最低，並依潮汐、光線與表演時刻來安排南海岸與海女站點。"}, {"icon": "users", "title": "小團體營運", "description": "更能靈活因應封閉與現場狀況", "iconBg": "bg-amber-50/80", "body": "小團體形式讓行程保持彈性——導遊可將海女表演改為博物館，或將萬丈窟改為日出樂園熔岩洞，而不致打亂整條路線。"}], "bookingSupportSteps": [{"timing": "預訂後", "title": "即時確認", "detail": "系統將寄送預訂確認信，內含行程路線摘要。"}, {"timing": "出發前12小時", "title": "出發前提醒", "detail": "提前告知天氣狀況及路線調整說明。"}, {"timing": "出發前一晚", "title": "最終接送通知", "detail": "您將收到確切的接送時間及聯絡資訊。"}, {"timing": "出發當天早晨", "title": "當日路線說明", "detail": "出發前簡要告知最新現場動態。"}, {"timing": "行程進行中", "title": "逐站導覽說明", "detail": "於每個停靠站視需要提供重要資訊。"}, {"timing": "行程結束後", "title": "行程後續支援", "detail": "如有需要，可提供後續支援及額外建議。"}], "staticQuestions": [{"id": "one-day", "question": "如果我在濟州只有一天，這條路線適合嗎？", "answer": "適合。這條路線專為在一天內遊覽濟州核心地標而設計——三處聯合國教科文組織遺址、海女文化、海崖與瀑布——節奏比一般一日遊更為緊湊。"}, {"id": "unesco", "question": "哪些景點是聯合國教科文組織遺址？", "answer": "共三處：漢拏山 1100 高地（屬漢拏山世界遺產區域）、城山日出峰，以及萬丈窟熔岩洞——皆位於濟州「火山島與熔岩洞」的登錄範圍內。海女表演同時也是聯合國教科文組織非物質文化遺產。"}, {"id": "haenyeo", "question": "如果海女表演取消了怎麼辦？", "answer": "露天的自由潛水示範取決於海象。若取消，路線將改為參觀鄰近的海女博物館，於室內訴說同一段女性潛水人的故事。"}, {"id": "manjanggul", "question": "萬丈窟是否總是開放？", "answer": "萬丈窟會不定期因保育與容量管制而封閉。封閉時，行程將改為參觀鄰近的日出樂園美千洞——另一處出自同一火山系統的熔岩洞。"}, {"id": "tiring", "question": "這條路線會讓人感到疲憊嗎？", "answer": "它比一般的小團體一日遊更為活躍：路線涵蓋島嶼大部分地區，並包含城山攀登、正房瀑布的樓梯，以及萬丈窟的洞穴步行。"}, {"id": "flight", "question": "如果我當天抵達或離開濟州，可以參加嗎？", "answer": "或許可以，但前提是傍晚有充裕的緩衝時間。若您的航班時間緊迫，則不建議選擇此路線。"}, {"id": "manjanggul-last", "question": "為什麼萬丈窟安排在最後？", "answer": "它正位於返回濟州市的途中，在一整天露天地形之後，作為涼爽、有遮蔽的聯合國教科文組織壓軸再合適不過。"}], "guestReviews": [], "reviewsSummary": {"averageRating": 0, "totalReviews": 0, "ratingDistribution": [{"stars": 5, "count": 0, "percentage": 0}, {"stars": 4, "count": 0, "percentage": 0}, {"stars": 3, "count": 0, "percentage": 0}, {"stars": 2, "count": 0, "percentage": 0}, {"stars": 1, "count": 0, "percentage": 0}], "highlights": []}, "sticky_booking_bar": {"note": "checkout_tour_id 於執行時從 Supabase／環境變數解析；不屬於靜態 JSONB 的一部分。", "price": {"amountLabel": "100", "originalPriceUsd": 112, "salePriceUsd": 100, "discountPercent": 11, "currency": "USD", "per": "person", "priceNote": "小團體雙語全島之旅（每人約 ₩138,000）。AtoC Korea 直營銷售；相較營運商基礎價已套用 11% 折扣。"}}, "matching_profile": {"product_type": "small_group", "route_type": "fixed_route", "region_type": "jeju_island_wide", "regio