  'USD',
  'person',
  '{"document_kind": "tour_product_full_page_v1", "schema_version": 7, "slug": "jeju-grand-highlights-loop", "locale": "es", "product_id": "jeju-grand-highlights-loop", "seo": {"pageTitle": "Gran Circuito de los Mejores Atractivos de Jeju — 3 sitios UNESCO + haenyeo | AtoC Korea", "metaDescription": "Circuito de Jeju de 10,5 horas en grupo reducido: humedal de Hallasan 1100, acantilados de Jusangjeolli, cascada Jeongbang, espectáculo en vivo de buceo libre de las haenyeo, Seongsan Ilchulbong y el tubo de lava de Manjanggul: tres sitios UNESCO en un solo día.", "primaryKeywords": ["Tour en grupo reducido por los mejores atractivos de Jeju", "Tour de un día por toda la isla de Jeju", "Tour UNESCO de un día por Jeju", "Tour a Seongsan Ilchulbong", "Tour al tubo de lava de Manjanggul", "Tour del espectáculo de haenyeo en Jeju"], "ogImage": "https://www.atockorea.com/images/tours/hallasan-1100/kakaotalk-20260510-230009595-21.webp", "title": "Gran Circuito de los Mejores Atractivos de Jeju · 3 sitios UNESCO + haenyeo + acantilados | AtoC", "description": "Tour de un día en grupo reducido por los mejores atractivos de toda la isla de Jeju: humedal de Hallasan 1100 → acantilado de Jusangjeolli → cascada Jeongbang → espectáculo de buceo libre de las haenyeo → Seongsan Ilchulbong → tubo de lava de Manjanggul. Tres sitios del Patrimonio Mundial de la UNESCO en un día de 10,5 horas."}, "catalog_card": {"slug": "jeju-grand-highlights-loop", "title": "Gran Circuito de los Mejores Atractivos de Jeju", "subtitle": "Los tres sitios UNESCO de Jeju, un espectáculo de haenyeo en vivo, acantilados marinos y una cascada que cae al océano: lo mejor de la isla en un solo día.", "region": "Ruta por toda la isla de Jeju", "duration": "10–10,5 horas", "stopsCount": 7, "rating": 0, "reviewCount": 0, "badges": ["Grupo pequeño", "3 sitios UNESCO", "Ideal para visitantes de un solo día"], "heroImage": "/images/tours/hallasan-1100/kakaotalk-20260510-230009595-21.webp", "thumbnail": "/images/tours/hallasan-1100/kakaotalk-20260510-230009595-21.webp", "priceLabel": "Desde US$100 por persona (antes $112, 11% de descuento)", "shortCardDescription": "Una ruta intensa por toda la isla que enlaza tres sitios del Patrimonio Mundial de la UNESCO —Hallasan, Seongsan Ilchulbong y el tubo de lava de Manjanggul— con un espectáculo en vivo de buceo libre de las haenyeo, los acantilados columnares de Jusangjeolli y la cascada Jeongbang que cae al océano. Los atractivos emblemáticos de Jeju, concentrados en un solo día.", "tags": ["Grupo pequeño", "Jeju", "Toda la isla", "UNESCO", "Cultura haenyeo", "destacados"]}, "headlineLine1": "Jeju Completo", "headlineLine2": "Hitos del Día", "price": {"amountLabel": "100", "originalPriceUsd": 112, "salePriceUsd": 100, "discountPercent": 11, "currency": "USD", "per": "person", "priceNote": "Tour bilingüe en grupo reducido por toda la isla (≈ ₩138,000 por persona). Venta directa de AtoC Korea; 11% de descuento aplicado sobre la tarifa base del operador."}, "hero": {"imageUrl": "/images/tours/hallasan-1100/kakaotalk-20260510-230009595-21.webp", "imagePosition": "center 35%", "tagline": "Un día intenso por toda la isla: un humedal alpino de Hallasan, acantilados marinos columnares, una cascada que cae al océano, un espectáculo en vivo de buceo libre de las haenyeo, el cono de tobas de Seongsan Ilchulbong y el tubo de lava de Manjanggul. Tres sitios del Patrimonio Mundial de la UNESCO más los dos hitos naturales más queridos de Jeju.", "pills": ["3 sitios UNESCO", "Cultura haenyeo", "Tour de un día en grupo reducido"], "meta": {"duration": "10–10,5 horas", "region": "Ruta por toda la isla de Jeju", "stops": "7 paradas", "rating": 0, "ratingStars": 0}}, "subnavItems": [{"id": "overview", "label": "Descripción general"}, {"id": "itinerary", "label": "Itinerario"}, {"id": "details", "label": "Detalles"}, {"id": "faq", "label": "FAQ"}, {"id": "reviews", "label": "Reseñas"}], "glanceItems": [{"icon": "camera", "label": "Valor fotográfico", "value": "Alto", "level": 5}, {"icon": "mountain", "label": "Pintoresco", "value": "Alto", "level": 5}, {"icon": "footprints", "label": "Caminata", "value": "Alto", "level": 4}, {"icon": "cloud-rain", "label": "Seguridad bajo la lluvia", "value": "Moderado", "level": 3}, {"icon": "users", "label": "Apto para familias", "value": "Moderado", "level": 3}, {"icon": "gauge", "label": "Equilibrio", "value": "Rápido", "level": 4}], "galleryItems": [{"id": 1, "type": "photo", "src": "/images/tours/hallasan-1100/kakaotalk-20260510-230009595-21.webp", "location": "Humedal de Altitud 1100 de Hallasan (Ramsar + UNESCO)", "alt": "Humedal de Altitud 1100 de Hallasan (Ramsar + UNESCO) — gallery image 1", "caption": "Humedal de Altitud 1100 de Hallasan (Ramsar + UNESCO) — photo 1"}, {"id": 2, "type": "photo", "src": "/images/tours/hallasan-1100/kakaotalk-20260510-230009595-22.webp", "location": "Humedal de Altitud 1100 de Hallasan (Ramsar + UNESCO)", "alt": "Humedal de Altitud 1100 de Hallasan (Ramsar + UNESCO) — gallery image 2", "caption": "Humedal de Altitud 1100 de Hallasan (Ramsar + UNESCO) — photo 2"}, {"id": 3, "type": "photo", "src": "/images/tours/hallasan-1100/kakaotalk-20260510-230009595-23.webp", "location": "Humedal de Altitud 1100 de Hallasan (Ramsar + UNESCO)", "alt": "Humedal de Altitud 1100 de Hallasan (Ramsar + UNESCO) — gallery image 3", "caption": "Humedal de Altitud 1100 de Hallasan (Ramsar + UNESCO) — photo 3"}, {"id": 4, "type": "photo", "src": "/images/tours/jusangjeolli/chatgpt-image-2026-2-15-10-01-04.webp", "location": "Acantilado de Daepo Jusangjeolli", "alt": "Acantilado de Daepo Jusangjeolli — gallery image 4", "caption": "Acantilado de Daepo Jusangjeolli — photo 4"}, {"id": 5, "type": "photo", "src": "/images/tours/jusangjeolli/kakaotalk-20260510-230028438-11.webp", "location": "Acantilado de Daepo Jusangjeolli", "alt": "Acantilado de Daepo Jusangjeolli — gallery image 5", "caption": "Acantilado de Daepo Jusangjeolli — photo 5"}, {"id": 6, "type": "photo", "src": "/images/tours/jusangjeolli/kakaotalk-20260510-230028438-12.webp", "location": "Acantilado de Daepo Jusangjeolli", "alt": "Acantilado de Daepo Jusangjeolli — gallery image 6", "caption": "Acantilado de Daepo Jusangjeolli — photo 6"}, {"id": 7, "type": "photo", "src": "/images/tours/jusangjeolli/kakaotalk-20260510-230028438-13.webp", "location": "Acantilado de Daepo Jusangjeolli", "alt": "Acantilado de Daepo Jusangjeolli — gallery image 7", "caption": "Acantilado de Daepo Jusangjeolli — photo 7"}, {"id": 8, "type": "photo", "src": "/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-15.webp", "location": "Cascada Jeongbang", "alt": "Cascada Jeongbang — gallery image 8", "caption": "Cascada Jeongbang — photo 8"}, {"id": 9, "type": "photo", "src": "/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-16.webp", "location": "Cascada Jeongbang", "alt": "Cascada Jeongbang — gallery image 9", "caption": "Cascada Jeongbang — photo 9"}, {"id": 10, "type": "photo", "src": "/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-17.webp", "location": "Cascada Jeongbang", "alt": "Cascada Jeongbang — gallery image 10", "caption": "Cascada Jeongbang — photo 10"}, {"id": 11, "type": "photo", "src": "/images/tours/jeju-haenyeo-museum/haenyeo-sunset-diving-ai.webp", "location": "Espectáculo de buceo libre de las haenyeo de Seongsan", "alt": "Espectáculo de buceo libre de las haenyeo de Seongsan — gallery image 11", "caption": "Espectáculo de buceo libre de las haenyeo de Seongsan — photo 11"}, {"id": 12, "type": "photo", "src": "/images/tours/seongsan-ilchulbong/kakaotalk-20260510-230028438-06.webp", "location": "Seongsan Ilchulbong", "alt": "Seongsan Ilchulbong — gallery image 12", "caption": "Seongsan Ilchulbong — photo 12"}, {"id": 13, "type": "photo", "src": "/images/tours/seongsan-ilchulbong/kakaotalk-20260510-230028438-07.webp", "location": "Seongsan Ilchulbong", "alt": "Seongsan Ilchulbong — gallery image 13", "caption": "Seongsan Ilchulbong — photo 13"}, {"id": 14, "type": "photo", "src": "/images/tours/seongsan-ilchulbong/kakaotalk-20260510-230028438-08.webp", "location": "Seongsan Ilchulbong", "alt": "Seongsan Ilchulbong — gallery image 14", "caption": "Seongsan Ilchulbong — photo 14"}, {"id": 15, "type": "photo", "src": "/images/tours/seongsan-ilchulbong/kakaotalk-20260510-230028438-09.webp", "location": "Seongsan Ilchulbong", "alt": "Seongsan Ilchulbong — gallery image 15", "caption": "Seongsan Ilchulbong — photo 15"}, {"id": 16, "type": "photo", "src": "/images/tours/ilchulland/chatgpt-image-2026-5-8-07-45-52.webp", "location": "Tubo de lava de Manjanggul", "alt": "Tubo de lava de Manjanggul — gallery image 16", "caption": "Tubo de lava de Manjanggul — photo 16"}], "itineraryStops": [{"number": 1, "time": "08:45", "duration": "45 min", "name": "Humedal de Altitud 1100 de Hallasan (Ramsar + UNESCO)", "category": "Humedal Alpino — Sitio Ramsar + dentro del Patrimonio Mundial UNESCO de Hallasan", "description": "**El Humedal de Altitud 1100 de Hallasan (한라산 1100고지 습지)** es un sistema de humedales alpinos de gran altitud en la meseta de Hallasan, ubicado **exactamente a 1.100 m sobre el nivel del mar** a lo largo de la **Ruta 1100 — la carretera nacional más alta de Corea** que une la ciudad de Jeju con Seogwipo Jungmun. \n\nEl sitio es un **Humedal de Importancia Internacional Ramsar (Sitio n.º 1893, designado el 12 de octubre de 2009)**, incluido dentro del **Sitio Patrimonio Mundial UNESCO de Hallasan (2007)**, la **Reserva de la Biosfera UNESCO de la Isla de Jeju (2002)** y el **Parque Nacional de Hallasan (1970)** — lo que convierte a este lugar en uno de los pocos del mundo con **cuatro designaciones internacionales/nacionales superpuestas**. \n\nEl humedal comprende **más de 16 marismas y pozas de agua dulce discontinuas** distribuidas a lo largo de una sección de meseta de baja pendiente que capta y retiene el agua de lluvia, formando **pequeños lagos permanentes y turberas** que albergan diversas comunidades florísticas con un endemismo significativo de Jeju. \n\nLa biodiversidad registrada incluye **3 especies de aves amenazadas y 1 especie vegetal amenazada en Corea**, además de especies de mamíferos, reptiles e insectos endémicas de la isla de Jeju. \n\nEl sitio recibió **900.000 visitantes en 2008** (datos del Centro de Visitantes del Monte Halla). Experiencia para el visitante: un **paseo entablado en bucle de 1 km** con miradores, señalización interpretativa y una pequeña exposición de historia natural en el punto de inicio. \n\n**El follaje otoñal (octubre–noviembre)** y **las escenas nevadas invernales (diciembre–febrero)** son las temporadas más fotografiadas; **primavera + verano** ofrecen visibilidad de la flora del humedal y las especies endémicas. \n\n**Entrada GRATUITA**; el **Área de Descanso 1100 (1100 휴게소)** adyacente dispone de baños interiores + cafetería + pequeña tienda de recuerdos. \n\n**La importancia cultural y religiosa** para las comunidades locales está documentada en la ficha Ramsar — peregrinaciones chamánicas históricas vinculadas a los espíritus del agua de la montaña.", "image": "/images/tours/hallasan-1100/kakaotalk-20260510-230009595-21.webp", "highlights": ["**Sitio Ramsar n.º 1893** (designado el 12 de oct. de 2009) — Humedal de Importancia Internacional", "**1.100 m sobre el nivel del mar** — en la **carretera nacional más alta** de Corea (Ruta 1100)", "**Cuádruple designación internacional** — Ramsar + Patrimonio Mundial UNESCO + Reserva de la Biosfera + Parque Nacional", "**Más de 16 humedales discontinuos** — marismas de agua dulce + pozas + turberas", "**3 aves amenazadas + 1 planta amenazada**; múltiples especies endémicas de Jeju", "**900.000 visitantes (2008)** — gestionado por el Centro de Visitantes del Monte Halla", "**Circuito de pasarela de madera de 1 km** con miradores y señalización interpretativa", "**Follaje otoñal + nieve invernal** = temporadas fotográficas emblemáticas", "**Entrada GRATUITA**; Área de Descanso 1100 adyacente (baños interiores + cafetería)"], "timeUsed": ["Llegada del autocar y aparcamiento en el Área de Descanso 1100 — ~5 min", "Circuito de pasarela y miradores — ~25 min", "Señalización interpretativa y exposición de historia natural — ~10 min", "Tiempo libre / baños de la cafetería — ~5 min"], "whyOnRoute": "El altiplano 1100 es la única parada de Hallasan que encaja en un circuito por toda la isla sin reserva ni una caminata de varias horas hasta la cima. Una breve pasarela alpina en la carretera más alta de Corea abre el día dentro del área del Patrimonio Mundial de la UNESCO de Hallasan, antes de que comience el largo trayecto hacia el sur.", "_poi_meta": {"poi_key": "hallasan_1100_wetland", "kb_version": "1.20", "verified_date": "2026-04-29", "sources": ["Ramsar Sites Information Service — 1100 Altitude Wetland (Site No. 1893)", "UNESCO Man and the Biosphere Programme — Jeju Island Biosphere Reserve", "Korea National Park Service — Hallasan National Park 1100 Wetland records", "Mt Halla Visitor Centre — visitor management documentation", "Jeju Special Self-Governing Province — Wetland Protected Area designation 2009"]}, "visitBasics": {"hours": "Abierto 24 horas (pasarela); centro de visitantes de 09:00 a 18:00", "closed": "La Carretera 1100 puede cerrar temporalmente durante nevadas intensas (dic–feb)", "admission": "Gratuito", "walking": "Fácil — pasarela de madera de 1 km; llana y accesible"}, "convenience": {"restroom": "Disponible en el centro de visitantes", "parking": "Aparcamiento gratuito en el centro de visitantes"}, "smartNotes": {"photo": "La pasarela que se adentra en el humedal con el Hallasan al fondo es la fotografía icónica; el otoño (octubre) ofrece colores dorados en la hierba", "facilities": "Centro de visitantes con aperitivos e información", "tip": "Lleve ropa de abrigo en capas — la temperatura es entre 5 y 10 °C más fría que en la costa de Jeju; compruebe las condiciones de la carretera en invierno; combínelo con las Cataratas Cheonjeyeon si desciende hacia el sur"}, "images": ["/images/tours/hallasan-1100/kakaotalk-20260510-230009595-21.webp", "/images/tours/hallasan-1100/kakaotalk-20260510-230009595-22.webp", "/images/tours/hallasan-1100/kakaotalk-20260510-230009595-23.webp"], "imageCredits": [{"url": "/images/tours/hallasan-1100/kakaotalk-20260510-230009595-21.webp", "source": "atoc-korea"}, {"url": "/images/tours/hallasan-1100/kakaotalk-20260510-230009595-22.webp", "source": "atoc-korea"}, {"url": "/images/tours/hallasan-1100/kakaotalk-20260510-230009595-23.webp", "source": "atoc-korea"}], "galleryItems": [{"id": 1, "type": "photo", "src": "/images/tours/hallasan-1100/kakaotalk-20260510-230009595-21.webp", "location": "Humedal de Altitud 1100 de Hallasan (Ramsar + UNESCO)", "caption": "Humedal de Altitud 1100 de Hallasan (Ramsar + UNESCO) — photo 1", "alt": "Humedal de Altitud 1100 de Hallasan (Ramsar + UNESCO) — gallery image 1"}, {"id": 2, "type": "photo", "src": "/images/tours/hallasan-1100/kakaotalk-20260510-230009595-22.webp", "location": "Humedal de Altitud 1100 de Hallasan (Ramsar + UNESCO)", "caption": "Humedal de Altitud 1100 de Hallasan (Ramsar + UNESCO) — photo 2", "alt": "Humedal de Altitud 1100 de Hallasan (Ramsar + UNESCO) — gallery image 2"}, {"id": 3, "type": "photo", "src": "/images/tours/hallasan-1100/kakaotalk-20260510-230009595-23.webp", "location": "Humedal de Altitud 1100 de Hallasan (Ramsar + UNESCO)", "caption": "Humedal de Altitud 1100 de Hallasan (Ramsar + UNESCO) — photo 3", "alt": "Humedal de Altitud 1100 de Hallasan (Ramsar + UNESCO) — gallery image 3"}]}, {"number": 2, "time": "10:00", "duration": "45 min", "name": "Acantilado de Daepo Jusangjeolli", "category": "Costa Volcánica — Lava con Juntas Columnares Hexagonales", "description": "**Daepo Jusangjeolli (대포 주상절리, ''Jisatgae'')** es un **tramo de 1 km de acantilado de basalto con juntas columnares hexagonales** en la costa de Jungmun — declarado **Monumento Natural n.º 443 el 6 de enero de 2005**. \n\nLas columnas se elevan **30–40 m** sobre el mar, dispuestas en **polígonos de 5 a 7 lados** perfectamente encajados (principalmente hexágonos) — una geometría producida cuando **la lava basáltica fundida de una erupción en el flanco del Hallasan (~250 000–140 000 años atrás) alcanzó el océano y se contrajo al enfriarse**, fracturándose de forma perpendicular a la superficie de enfriamiento. \n\nA nivel mundial, las juntas columnares son más conocidas en **Giant''s Causeway (Reino Unido)**, **Devils Postpile (EE. UU.)** y **la Cueva de Fingal (Escocia)** — Jusangjeolli es el **ejemplo más destacado de Asia Oriental** y el más accesible. \n\nEl **paseo marítimo de 800 m en bucle** lleva a los visitantes hasta el borde del acantilado con barandilla, directamente sobre las columnas; **en días de marea alta, las olas rompen contra las columnas y lanzan spray hasta 20 m de altura**, en ocasiones por encima de la barandilla. \n\nEntrada: **Adultos ₩2 000 / Jóvenes ₩1 000 / GRATIS menores de 7 años y mayores de 65**. El lugar forma parte del **Geoparque Global de Jeju (designación UNESCO octubre de 2010)** — uno de los **13 geositios oficiales** de la isla, junto a Seongsan Ilchulbong, el Tubo de Lava de Manjanggul y Suwolbong. \n\nLa plataforma superior del acantilado es **totalmente accesible** (para sillas de ruedas y cochecitos). Tres miradores a lo largo del recorrido ofrecen distintos ángulos de las columnas: el **primer mirador** muestra las columnas de perfil (ideal para capturar la geometría hexagonal), el **mirador intermedio** permite mirar directamente hacia abajo para ver los patrones en la parte superior de las columnas, y el **mirador del fondo** capta el trazado costero de 1 km con el Hallasan de fondo en días despejados. \n\n**Ventana óptima para fotografía: 14:00–16:00**, cuando la luz del sol en descenso ilumina de frente las caras de las columnas; las visitas al atardecer ofrecen composiciones en silueta, pero pierden la textura del detalle columnar. Horario: **09:00–18:00 (última entrada 17:30)**, abierto todo el año.", "image": "/images/tours/jusangjeolli/chatgpt-image-2026-2-15-10-01-04.webp", "highlights": ["**Monumento Natural n.º 443** — declarado el **6 de enero de 2005**, el Monumento Natural costero de Jeju más reciente", "Las columnas se elevan **30–40 m**, dispuestas en **polígonos de 5 a 7 lados** (principalmente hexágonos) a lo largo de **1 km** de costa", "Formación: **la lava del flanco del Hallasan se enfrió en el mar hace ~250 000–140 000 años**, contrayéndose de forma perpendicular a la superficie de enfriamiento", "**El principal sitio de juntas columnares de Asia Oriental** — comparable a Giant''s Causeway, Devils Postpile y la Cueva de Fingal", "**Spray de hasta 20 m en días de marea alta** — ventana para fotografía de olas espumosas", "**Paseo en bucle de 0,8 km**, ~15 min a pie — plataforma accesible para todos, con acceso para sillas de ruedas y cochecitos", "Parte del **Geoparque Global de Jeju (UNESCO octubre de 2010)** — 13 geositios distribuidos por toda la isla", "Entrada: **₩2 000 adultos / ₩1 000 jóvenes / GRATIS menores de 7 años y mayores de 65**", "La cima del Hallasan es visible al norte en días despejados, **directamente aguas abajo** en términos geológicos"], "timeUsed": ["Aparcamiento + compra de entrada + acceso — ~5 min", "Caminata hasta el primer mirador — ~5 min", "Vista del borde del acantilado + fotos — ~15 min", "Continuar el recorrido por el paseo marítimo — ~10 min", "Regreso al autocar — ~10 min"], "whyOnRoute": "Jusangjeolli es la demostración individual más eficiente de la geología volcánica de Jeju: una breve parada en la costa sur que resume visualmente la historia del encuentro entre la lava y el mar, de camino entre el altiplano de Hallasan y la cascada Jeongbang.", "_poi_meta": {"poi_key": "daepo_jusangjeolli_cliff", "kb_version": "1.18", "verified_date": "2026-04-29", "sources": ["Cultural Heritage Administration — Natural Monument No. 443 designation (2005-01-06)", "Jeju Global Geopark official site (geopark.jeju.go.kr)", "UNESCO Global Geoparks Network — Jeju (2010 designation)", "VisitJeju — Daepo Jusangjeolli", "Korea Geological Survey — Jeju basalt formation studies"]}, "visitBasics": {"hours": "09:00–18:00 (última entrada 17:40)", "closed": "Abierto todo el año", "admission": "2 000 KRW adultos / 1 000 KRW niños y adolescentes", "walking": "Fácil a moderado"}, "convenience": {"restroom": "Zona de entrada", "parking": "Aparcamiento disponible (estacionamiento de pago)"}, "smartNotes": {"photo": "La dirección del viento, el spray y la luz lateral pueden cambiar el ambiente rápidamente, por lo que los encuadres amplios de la costa funcionan especialmente bien aquí.", "facilities": "La zona de entrada está bien equipada y el camino hacia el mirador es relativamente sencillo.", "tip": "Incluso en un día soleado, la costa suele sentirse más fría y ventosa que el interior de Jeju."}, "images": ["/images/tours/jusangjeolli/chatgpt-image-2026-2-15-10-01-04.webp", "/images/tours/jusangjeolli/kakaotalk-20260510-230028438-11.webp", "/images/tours/jusangjeolli/kakaotalk-20260510-230028438-12.webp", "/images/tours/jusangjeolli/kakaotalk-20260510-230028438-13.webp", "/images/tours/jusangjeolli/photo-005.webp"], "imageCredits": [{"url": "/images/tours/jusangjeolli/chatgpt-image-2026-2-15-10-01-04.webp", "source": "atoc-korea"}, {"url": "/images/tours/jusangjeolli/kakaotalk-20260510-230028438-11.webp", "source": "atoc-korea"}, {"url": "/images/tours/jusangjeolli/kakaotalk-20260510-230028438-12.webp", "source": "atoc-korea"}, {"url": "/images/tours/jusangjeolli/kakaotalk-20260510-230028438-13.webp", "source": "atoc-korea"}, {"url": "/images/tours/jusangjeolli/photo-005.webp", "source": "atoc-korea"}], "galleryItems": [{"id": 1, "type": "photo", "src": "/images/tours/jusangjeolli/chatgpt-image-2026-2-15-10-01-04.webp", "location": "Acantilado de Daepo Jusangjeolli", "caption": "Acantilado de Daepo Jusangjeolli — photo 1", "alt": "Acantilado de Daepo Jusangjeolli — gallery image 1"}, {"id": 2, "type": "photo", "src": "/images/tours/jusangjeolli/kakaotalk-20260510-230028438-11.webp", "location": "Acantilado de Daepo Jusangjeolli", "caption": "Acantilado de Daepo Jusangjeolli — photo 2", "alt": "Acantilado de Daepo Jusangjeolli — gallery image 2"}, {"id": 3, "type": "photo", "src": "/images/tours/jusangjeolli/kakaotalk-20260510-230028438-12.webp", "location": "Acantilado de Daepo Jusangjeolli", "caption": "Acantilado de Daepo Jusangjeolli — photo 3", "alt": "Acantilado de Daepo Jusangjeolli — gallery image 3"}, {"id": 4, "type": "photo", "src": "/images/tours/jusangjeolli/kakaotalk-20260510-230028438-13.webp", "location": "Acantilado de Daepo Jusangjeolli", "caption": "Acantilado de Daepo Jusangjeolli — photo 4", "alt": "Acantilado de Daepo Jusangjeolli — gallery image 4"}, {"id": 5, "type": "photo", "src": "/images/tours/jusangjeolli/photo-005.webp", "location": "Acantilado de Daepo Jusangjeolli", "caption": "Acantilado de Daepo Jusangjeolli — photo 5", "alt": "Acantilado de Daepo Jusangjeolli — gallery image 5"}]}, {"number": 3, "time": "11:05", "duration": "60 min", "name": "Cascada Jeongbang", "category": "Cascada Costera — Cae Directamente al Océano (Única en Asia)", "description": "**Las Cataratas Jeongbang (정방폭포, ''cataratas que caen directamente al mar'')** son la **única cascada en Asia que cae directamente al océano** — una **caída vertical de 23 m** desde un acantilado de basalto al Pacífico, sin poza intermedia ni desembocadura de lecho fluvial. \n\nLa cascada mide **8 m de ancho** con una poza basal de 5 m que alcanza el mar abierto en cada marea. Esta distinción geográfica única es la razón por la que Jeongbang es una de las **''Yeongjusipgyeong (영주십경, Las 10 Maravillas Escénicas de Jeju)''** — un canon literario de la era Joseon de los paisajes más poéticos de la isla. \n\nLa lista Yeongjusipgyeong, codificada por el **erudito confuciano del siglo XVIII Lee Won-jo (이원조)**, incluye también el Amanecer de Seongsan, la cima del Hallasan y Cheonjeyeon — lo que significa que el circuito de hoy abarca **3 de las 10** en un solo día. Tallada en la cara del acantilado junto a las cataratas se encuentra la inscripción **''Seobulgwacha (서불과차, Seobul se dirigió de vuelta al oeste)''**, atribuida a **Xu Fu (서복)**, el legendario alquimista de la dinastía Qin enviado por el **Emperador Qin Shi Huang (~219 a. C.)** en busca del elixir de la inmortalidad. \n\nLa tradición local cuenta que pasó por aquí en su camino de regreso — la inscripción es la raíz etimológica del topónimo **''Seogwipo'' (서귀포, ''donde Seo se dirigió de regreso'')**. \n\nEl acceso es a través de **130 escalones de piedra** que descienden a la cala (bastante empinados — se recomienda calzado cómodo para las rodillas). Entrada: **Adulto ₩2.000 / Joven ₩1.000 / GRATIS para menores de 7 años y mayores de 65**. \n\nEl fresco microclima generado por el estruendoso oleaje en la base es un reconocido refugio en verano. Las **haenyeo locales (해녀, mujeres buceadoras — Patrimonio Cultural Inmaterial de la UNESCO 2016)** venden a veces erizo de mar fresco, abulón y caracola directamente en la cala en días de mar en calma — una rara oportunidad fotográfica para ver a la comunidad de buceo trabajando fuera de su contexto formal de museo.", "image": "/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-15.webp", "highlights": ["**La única cascada de Asia que cae directamente al océano** — caída vertical de 23 m, sin lecho fluvial", "Las cataratas miden **8 m de ancho** con una poza basal de 5 m que desemboca en el Pacífico con cada marea", "Una de las **''Yeongjusipgyeong''** — Las 10 Maravillas Escénicas de Jeju de la era Joseon", "**Inscripción ''Seobulgwacha''** — atribuida a Xu Fu (alquimista de Qin, ~219 a. C.), origen del topónimo ''Seogwipo''", "**130 escalones de piedra** hasta la cala — se recomienda calzado que cuide las rodillas", "Entrada **₩2.000 adultos / ₩1.000 jóvenes / GRATIS menores de 7 años + mayores de 65**", "Microclima refrescado por la bruma en la base — alivio natural en verano", "Las **haenyeo (해녀, buzos mujeres)** locales a veces venden capturas frescas en la cala en días de calma", "La ''hora dorada'' fotográfica suele ser entre las **14:00 y las 14:30**, cuando el sol ilumina de frente la cascada desde el oeste"], "timeUsed": ["Entrada + taquilla + descenso (130 escalones) — ~10 min", "Mirador de la cala + fotografía de la cascada — ~25 min", "Sendero opcional por el acantilado + inscripción de Seobul — ~10 min", "Ascenso de regreso al autocar — ~10 min", "Margen de tiempo — ~5 min"], "whyOnRoute": "Jeongbang —la única cascada de Asia que cae directamente al mar— se encuentra a minutos del distrito gastronómico de Seogwipo, por lo que encaja justo antes de la pausa del mediodía sin ningún rodeo.", "_poi_meta": {"poi_key": "jeongbang_falls", "kb_version": "1.18", "verified_date": "2026-04-29", "sources": ["Korea Cultural Heritage Foundation — Yeongjusipgyeong canon", "VisitJeju — Jeongbang Pokpo official listing", "Seogwipo City tourism office — admission and access", "Korea Geological Survey — coastal waterfall inventory", "Jeju Folklore Records — Xu Fu / Seobulgwacha inscription study"]}, "visitBasics": {"hours": "09:00–17:20", "closed": "Abierto todo el año", "admission": "KRW 2.000 adultos / KRW 1.000 niños", "walking": "Moderado, con escaleras"}, "convenience": {"restroom": "Zona de entrada", "parking": "Aparcamiento disponible"}, "smartNotes": {"photo": "La zona rocosa de abajo ofrece tomas con mucha atmósfera, pero el terreno irregular y la bruma del mar pueden hacer que la experiencia resulte más exigente de lo esperado.", "facilities": "Las instalaciones básicas se encuentran cerca de la entrada.", "tip": "Debido a las escaleras y el camino rocoso, la visita suele sentirse más activa físicamente sobre el terreno de lo que parece en el mapa."}, "images": ["/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-15.webp", "/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-16.webp", "/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-17.webp"], "imageCredits": [{"url": "/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-15.webp", "source": "atoc-korea"}, {"url": "/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-16.webp", "source": "atoc-korea"}, {"url": "/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-17.webp", "source": "atoc-korea"}], "galleryItems": [{"id": 1, "type": "photo", "src": "/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-15.webp", "location": "Cascada Jeongbang", "caption": "Cascada Jeongbang — photo 1", "alt": "Cascada Jeongbang — gallery image 1"}, {"id": 2, "type": "photo", "src": "/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-16.webp", "location": "Cascada Jeongbang", "caption": "Cascada Jeongbang — photo 2", "alt": "Cascada Jeongbang — gallery image 2"}, {"id": 3, "type": "photo", "src": "/images/tours/jeongbang-falls/kakaotalk-20260510-230028438-17.webp", "location": "Cascada Jeongbang", "caption": "Cascada Jeongbang — photo 3", "alt": "Cascada Jeongbang — gallery image 3"}]}, {"number": 4, "time": "12:15", "duration": "60 min", "name": "Almuerzo — Local de Seogwipo", "category": "Pausa de Mediodía — Gastronomía Local de Seogwipo", "description": "**Pausa de 60 minutos en el centro de Seogwipo (서귀포)** — la ciudad sureña de Jeju, famosa por los mariscos frescos desembarcados en el **Mercado Maeil Olle de Seogwipo (서귀포매일올레시장)** y la costa rica en abulones. Rotación predeterminada según la temporada y el tamaño del grupo: **galchi-jorim (갈치조림, guiso de pez sable estofado)** en un restaurante especializado de Seogwipo cuando los barcos desembarcan en temporada (sep–feb), **jeonbok-bibimbap (전복비빔밥, abulón sobre arroz)** durante todo el año en un local frente al mercado, o **heuk-doeji gui (흑돼지구이, BBQ de cerdo negro de Jeju)** para los huéspedes que prefieren carne a la parrilla. \n\nEl cerdo negro (***Sus scrofa* domesticus, variedad negra de Jeju**) fue designado **Material del Patrimonio Cultural N.º 5 (2015)** y sigue siendo una raza protegida de Jeju. Alternativa vegetariana bajo petición: **bibim-guksu (비빔국수, fideos fríos picantes)** con verduras de temporada. \n\nEl lugar del almuerzo se encuentra **a 5 minutos a pie de las Cataratas Jeongbang** — los huéspedes con ganas de un café rápido tras el almuerzo pueden detenerse en la hilera de teterías/cafés del mercado antes de continuar a pie.", "image": null, "highlights": ["**Seogwipo** central — capital pesquera y marisquera del sur de Jeju", "**Galchi-jorim (pez sable)** en temporada (sep–feb), **jeonbok-bibimbap** durante todo el año", "Opción **heuk-doeji (cerdo negro de Jeju)** — Material del Patrimonio Cultural N.º 5 (2015)", "Alternativa **bibim-guksu vegetariana** bajo petición", "El lugar del almuerzo está **a 5 minutos a pie de la entrada de las Cataratas Jeongbang** — tránsito en autobús mínimo", "Los requisitos dietéticos del grupo se recogen al inicio del recorrido; el menú se confirma con antelación"], "timeUsed": ["Caminata hasta el lugar del almuerzo — ~5 min", "Pedido + comida + bebidas — ~45 min", "Caminata hasta la entrada de las Cataratas Jeongbang — ~5 min", "Margen de tiempo — ~5 min"], "whyOnRoute": "El almuerzo se sitúa en el centro de Seogwipo, entre las paradas de la costa sur y el largo trayecto hacia el este, de modo que el grupo recupera energía para el ascenso y la cueva de la tarde.", "visitBasics": {"hours": "Depende del horario de apertura del restaurante", "closed": "Varía según el establecimiento", "admission": "La comida se paga en el lugar salvo que se especifique lo contrario", "walking": "Mínimo"}, "convenience": {"restroom": "Dentro del restaurante", "parking": "Estacionamiento disponible"}, "smartNotes": {"photo": "Dado que la mayor parte del día se centra en paisajes, las fotos de comida pueden ayudar a variar el ritmo visual del recorrido.", "facilities": "Las instalaciones relacionadas con la restauración suelen ser más que suficientes.", "tip": "Es mejor comer aquí a un ritmo tranquilo que apresurarse y perder energía para la tarde."}, "images": []}, {"time": "14:00", "duration": "45 min", "name": "Espectáculo de buceo libre de las haenyeo de Seongsan", "category": "Patrimonio Inmaterial de la UNESCO — Actuación en vivo de las mujeres buceadoras", "description": "Las haenyeo (mujeres buceadoras) de Jeju están reconocidas como Patrimonio Cultural Inmaterial de la Humanidad de la UNESCO (2016). En la cala del lado sur de Seongsan Ilchulbong, buceadoras veteranas —muchas de entre 60 y 80 años— ofrecen una demostración diaria de buceo libre, normalmente alrededor de las 13:30 y las 15:00. Abren con los tradicionales cantos de trabajo y luego se sumergen entre 5 y 10 m sin equipo de respiración para recolectar caracola, erizo de mar y abulón, emergiendo con el característico silbido de respiración ''sumbi-sori'' que les permite liberar el aire tras una larga inmersión. Después del espectáculo, las buceadoras venden su captura fresca cortada como sashimi justo junto al agua. Es un encuentro raro y vivo con una cultura de buceo matrifocal de 400 años que va desapareciendo poco a poco a medida que las buceadoras que quedan envejecen. La demostración se realiza al aire libre y depende de las condiciones del mar; los días en que se cancela, la ruta visita en su lugar el Museo de las Haenyeo en la cercana Hado, que cuenta la misma historia en interiores a través de equipo de buceo, historia y películas.", "image": "/images/tours/jeju-haenyeo-museum/haenyeo-sunset-diving-ai.webp", "highlights": ["Patrimonio Cultural Inmaterial de la UNESCO (2016) — las mujeres buceadoras de Jeju", "Demostración de buceo libre en vivo en la cala de Seongsan (alrededor de las 13:30 / 15:00)", "Cantos de buceo tradicionales y la característica respiración ''sumbi-sori''", "Alternativa por cancelación: el Museo de las Haenyeo, en interiores, cuenta la misma historia"], "timeUsed": ["Bajada a pie hasta la cala de las haenyeo — ~5 min", "Demostración de buceo libre + cantos de buceo — ~25 min", "Captura fresca / sashimi junto al agua — ~10 min", "Regreso al vehículo — ~5 min"], "whyOnRoute": "El espectáculo de haenyeo añade la capa humana y cultural a un día de formaciones volcánicas; y como se encuentra justo al pie de Seongsan, no supone ninguna conducción adicional antes del ascenso.", "_poi_meta": {"poi_key": "jeju_haenyeo_museum", "kb_version": "1.29", "verified_date": "2026-06-23", "sources": ["VisitKorea", "UNESCO ICH 2016", "Jeju Haenyeo Museum"]}, "smartNotes": {"photo": "Las buceadoras entrando al agua con sus trajes de neopreno, y la captura fresca dispuesta sobre las rocas después", "facilities": "Los puestos de las buceadoras venden sashimi de erizo de mar, caracola y abulón fresco recién extraído del buceo", "tip": "El horario del espectáculo varía con el mar y la temporada; el guía lo confirma el mismo día. Si se cancela, visitará en su lugar el Museo de las Haenyeo."}, "convenience": {"restroom": "Disponible en la plaza de entrada de Seongsan Ilchulbong", "parking": "Compartido con el aparcamiento de Seongsan Ilchulbong"}, "visitBasics": {"hours": "Demostración al aire libre normalmente alrededor de las 13:30 y las 15:00 (depende de la temporada y el clima)", "closed": "Se cancela con mar agitado o mal tiempo; el Museo de las Haenyeo cierra los lunes", "admission": "Gratuito para ver la demostración; Museo de las Haenyeo (alternativa) unos ₩1,100 adultos", "walking": "Mínima — un breve sendero llano que baja hasta la cala"}, "images": ["/images/tours/jeju-haenyeo-museum/haenyeo-sunset-diving-ai.webp"], "imageCredits": [{"url": "/images/tours/jeju-haenyeo-museum/haenyeo-sunset-diving-ai.webp", "source": "atoc-korea"}], "galleryItems": [], "number": 5}, {"number": 6, "time": "14:55", "duration": "90 min", "name": "Seongsan Ilchulbong", "category": "Cono de Tobas UNESCO — Pico del Amanecer (Triple Designación UNESCO)", "description": "**Seongsan Ilchulbong (성산일출봉, ''Pico del Amanecer'')** es un **cono hidrovolcánico de tipo surtseyano de 5.000 años de antigüedad** — una rara forma de relieve creada cuando una erupción basáltica submarina irrumpió en la superficie del mar, el magma encontró el agua del océano y la explosión de vapor resultante formó un **cráter en forma de fortaleza de 182 m** de altura en lugar de un cono de lava típico. \n\nEl resultado es lo que la UNESCO denomina formalmente **''un ejemplo excepcional de un edificio volcánico emergente de tipo surtseyano''**. El cráter mide **600 m de ancho × 90 m de profundidad**, rodeado por **99 rocas dentadas en el borde** que la tradición local compara con una corona de piedra. \n\nSeongsan posee la **triple designación UNESCO**: **Patrimonio Natural Mundial (inscrito el 02-07-2007)** como parte de la propiedad **''Isla Volcánica de Jeju y Tubos de Lava''**, **Reserva de la Biosfera (2002)** y **Geoparque Mundial (10-2010)** — una combinación igualada únicamente por el propio Hallasan entre los sitios coreanos. \n\n**18 cuevas militares japonesas de la Segunda Guerra Mundial** (refugios para embarcaciones kamikazes, 1945) están excavadas en la base marítima. Sendero: **0,8 km de ida, ~140 m de desnivel, 60 min de ida y vuelta** por amplios escalones de piedra. \n\nLas **demostraciones de haenyeo (해녀)** se realizan **diariamente a las 14:00 (1 espectáculo/día)** en la cala rocosa bajo el cono — las buceadoras de Jeju (Patrimonio Cultural Inmaterial de la UNESCO 2016) se sumergen sin equipo de buceo. Entrada actualizada en **abril de 2025**: **Adultos ₩5.000 / Jóvenes y niños ₩2.500 / Grupo adultos ₩1.600**, gratis menores de 7 años y mayores de 65. \n\nLa plataforma de la cumbre también forma parte del canon de las **Yeongjusipgyeong (Las 10 Vistas Panorámicas de Jeju)**, y sigue siendo el principal destino de **peregrinación anual al amanecer de Año Nuevo** en Corea — más de 50.000 visitantes ascienden antes del alba el 1 de enero, con programación del festival municipal del amanecer desde 1995. \n\nLa **Isla Udo (우도, ''Isla de la Vaca'')** — la mayor isla volcánica secundaria de Corea — se distingue claramente a 4 km de la costa desde la cima, accesible en **ferry de 15 min desde el Puerto de Seongsan** (₩10.500 ida y vuelta) para los visitantes con tiempo extra en otro itinerario.", "image": "/images/tours/seongsan-ilchulbong/kakaotalk-20260510-230028438-06.webp", "highlights": ["**Triple UNESCO**: Patrimonio Mundial 02-07-2007 + Reserva de la Biosfera 2002 + Geoparque Mundial 10-2010", "**5.000 años de antigüedad** — erupción hidrovolcánica de tipo surtseyano, nacida de la explosión de vapor al encontrarse el magma con el agua del mar", "Cráter de **600 m de ancho × 90 m de profundidad**, rodeado por **99 rocas dentadas** (la ''corona de piedra'')", "**182 m sobre el nivel del mar** — 0,8 km / ~140 m de desnivel, 60 min de ida y vuelta por sendero de escalones de piedra", "**18 cuevas militares japonesas de la Segunda Guerra Mundial** en la base — refugios para embarcaciones kamikazes en 1945", "**Demostraciones de haenyeo diaria a las 14:00 (1 espectáculo/día)** en la cala junto al mar — Patrimonio Inmaterial de la UNESCO 2016", "**Entrada actualizada en abril de 2025**: Adultos ₩5.000 / Jóvenes ₩2.500 / GRATIS menores de 7 años y mayores de 65", "Horario de primavera/otoño **05:00–19:00** (última entrada 18:20)", "**Cierra el primer lunes de cada mes** (día de descanso ocasional)"], "timeUsed": ["Estacionamiento + entrada + breve explicación inicial — ~10 min", "Ascenso a la plataforma de la cima (0,8 km / 140 m de desnivel) — ~30 min", "Vistas desde la cima + fotos en el borde del cráter — ~20 min", "Descenso — ~20 min", "Observación opcional de haenyeo en la base (demostración a las 14:00) — ~10 min"], "whyOnRoute": "Seongsan Ilchulbong es el ascenso emblemático del día: un cono de tobas con triple designación UNESCO justo al lado de la cala de las haenyeo, de modo que el grupo puede ver a las buceadoras y luego ascender sin conducción adicional.", "_poi_meta": {"poi_key": "seongsan_ilchulbong", "kb_version": "1.18", "verified_date": "2026-04-29", "sources": ["UNESCO WHC inscription 1264 (Jeju Volcanic Island and Lava Tubes, 2007-07-02)", "UNESCO Global Geoparks Network — Jeju (2010-10 designation)", "Cultural Heritage Administration — Natural Monument designation 2000-07-19", "Seongsan Ilchulbong official site (seongsan.kr) — April 2025 admission update", "Jeju Haenyeo Museum — UNESCO Intangible 2016 inscription record"]}, "visitBasics": {"hours": "Los horarios de acceso de pago pueden variar según la temporada", "closed": "Cerrado el primer lunes de cada mes (o el día siguiente si coincide con un festivo)", "admission": "KRW 5.000 adultos / KRW 2.500 niños", "walking": "Moderado a moderadamente exigente si se opta por llegar a la cima"}, "convenience": {"restroom": "Zona baja e instalaciones circundantes", "parking": "Amplio aparcamiento disponible"}, "smartNotes": {"photo": "En lugar de fotografiar únicamente la cima, las composiciones más amplias que incluyan tanto el cráter como la línea costera suelen resultar más satisfactorias.", "facilities": "Las instalaciones en la zona de la base están bien desarrolladas.", "tip": "La afluencia de visitantes, el estado del tiempo y el nivel físico del grupo pueden influir en la exigencia y el disfrute de la experiencia en la cima."}, "images": ["/images/tours/seongsan-ilchulbong/kakaotalk-20260510-230028438-06.webp", "/images/tours/seongsan-ilchulbong/kakaotalk-20260510-230028438-07.webp", "/images/tours/seongsan-ilchulbong/kakaotalk-20260510-230028438-08.webp", "/images/tours/seongsan-ilchulbong/kakaotalk-20260510-230028438-09.webp", "/images/tours/seongsan-ilchulbong/kakaotalk-20260510-230028438-10.webp", "/images/tours/seongsan-ilchulbong/photo-006.webp", "/images/tours/seongsan-ilchulbong/seongsan-haenyeo-show-ai.webp"], "imageCredits": [{"url": "/images/tours/seongsan-ilchulbong/kakaotalk-20260510-230028438-06.webp", "source": "atoc-korea"}, {"url": "/images/tours/seongsan-ilchulbong/kakaotalk-20260510-230028438-07.webp", "source": "atoc-korea"}, {"url": "/images/tours/seongsan-ilchulbong/kakaotalk-20260510-230028438-08.webp", "source": "atoc-korea"}, {"url": "/images/tours/seongsan-ilchulbong/kakaotalk-20260510-230028438-09.webp", "source": "atoc-korea"}, {"url": "/images/tours/seongsan-ilchulbong/kakaotalk-20260510-230028438-10.webp", "source": "atoc-korea"}, {"url": "/images/tours/seongsan-ilchulbong/photo-006.webp", "source": "atoc-korea"}, {"url": "/images/tours/seongsan-ilchulbong/seongsan-haenyeo-show-ai.webp", "source": "atoc-korea"}, {"url": "/images/tours/seongsan-ilchulbong/photo-006.webp", "source": "atoc-korea"}], "galleryItems": [{"id": 1, "type": "photo", "src": "/images/tours/seongsan-ilchulbong/kakaotalk-20260510-230028438-06.webp", "location": "Seongsan Ilchulbong", "caption": "Seongsan Ilchulbong — photo 1", "alt": "Seongsan Ilchulbong — gallery image 1"}, {"id": 2, "type": "photo", "src": "/images/tours/seongsan-ilchulbong/kakaotalk-20260510-230028438-07.webp", "location": "Seongsan Ilchulbong", "caption": "Seongsan Ilchulbong — photo 2", "alt": "Seongsan Ilchulbong — gallery image 2"}, {"id": 3, "type": "photo", "src": "/images/tours/seongsan-ilchulbong/kakaotalk-20260510-230028438-08.webp", "location": "Seongsan Ilchulbong", "caption": "Seongsan Ilchulbong — photo 3", "alt": "Seongsan Ilchulbong — gallery image 3"}, {"id": 4, "type": "photo", "src": "/images/tours/seongsan-ilchulbong/kakaotalk-20260510-230028438-09.webp", "location": "Seongsan Ilchulbong", "caption": "Seongsan Ilchulbong — photo 4", "alt": "Seongsan Ilchulbong — gallery image 4"}, {"id": 5, "type": "photo", "src": "/images/tours/seongsan-ilchulbong/kakaotalk-20260510-230028438-10.webp", "location": "Seongsan Ilchulbong", "caption": "Seongsan Ilchulbong — photo 5", "alt": "Seongsan Ilchulbong — gallery image 5"}, {"id": 6, "type": "photo", "src": "/images/tours/seongsan-ilchulbong/photo-006.webp", "location": "Seongsan Ilchulbong", "caption": "Seongsan Ilchulbong — photo 6", "alt": "Seongsan Ilchulbong — gallery image 6"}, {"id": 7, "type": "photo", "src": "/images/tours/seongsan-ilchulbong/seongsan-haenyeo-show-ai.webp", "location": "Seongsan Ilchulbong", "caption": "Seongsan Ilchulbong — photo 12", "alt": "Seongsan Ilchulbong — gallery image 12"}], "liveStatusWidget": "haenyeo"}, {"time": "16:55", "duration": "50 min", "name": "Tubo de lava de Manjanggul", "category": "Tubo de lava UNESCO — Final en cueva del Patrimonio Natural Mundial", "description": "Manjanggul es uno de los mejores tubos de lava del mundo y la cueva que está en el corazón de la inscripción UNESCO de Jeju. Se formó hace aproximadamente entre 100.000 y 300.000 años, cuando la lava del sistema volcánico de Geomunoreum drenó hacia el mar, dejando un túnel de unos 7,4 km de longitud. Un tramo de 1 km está abierto a los visitantes y termina en una columna de lava de 7,6 m —la columna de lava más alta conocida de la Tierra—, formada donde la lava se derramó desde un pasaje superior. Por el camino, la cueva muestra rasgos volcánicos de manual: estalactitas de lava, líneas de flujo que rayan las paredes, lava cordada en forma de cuerda en el suelo, coral de cueva y una roca ''tortuga de lava'' que, por coincidencia, recuerda la forma de la propia isla de Jeju. Forma parte del sitio del Patrimonio Mundial de la UNESCO ''Isla Volcánica de Jeju y Tubos de Lava'', inscrito en 2007. La cueva mantiene una temperatura estable de aproximadamente 11–21 °C durante todo el año, por lo que es fresca en verano y templada en invierno, y un refugio natural en un día de lluvia. El suelo es irregular, húmedo y poco iluminado, y el recorrido público es de aproximadamente 1 km de ida y vuelta, que toma entre 30 y 45 minutos. Manjanggul cierra periódicamente por conservación y gestión del aforo; esos días la ruta visita la cercana cueva Micheon de Ilchul Land, otro tubo de lava del mismo sistema.", "image": "/images/tours/ilchulland/chatgpt-image-2026-5-8-07-45-52.webp", "highlights": ["Parte del sitio del Patrimonio Mundial de la UNESCO ''Isla Volcánica de Jeju y Tubos de Lava'' (2007)", "Termina en la columna de lava más alta conocida del mundo — unos 7,6 m", "1 km de pasaje accesible dentro de un sistema de tubo de lava de 7,4 km", "Fresca, 11–21 °C todo el año — el refugio natural del día frente a la lluvia y el calor"], "timeUsed": ["Llegada + aparcamiento en Manjanggul — ~5 min", "Caminata de entrada hasta la columna de lava de 7,6 m — ~20 min", "Columna de lava + caminata de regreso — ~20 min", "Margen / baños en la entrada — ~5 min"], "whyOnRoute": "Manjanggul corona el circuito con el tercer sitio del Patrimonio Natural de la UNESCO y la única parada del día cubierta y en interiores. Se encuentra a unos 30 minutos de Seongsan, de camino de regreso hacia la ciudad de Jeju, por lo que cierra el circuito sin añadir distancia.", "_poi_meta": {"poi_key": "manjanggul_lava_tube", "kb_version": "1.29", "verified_date": "2026-06-23", "sources": ["UNESCO World Heritage 2007", "Jeju World Natural Heritage Center", "VisitKorea"]}, "smartNotes": {"photo": "La columna de lava de 7,6 m al final del sendero y la roca ''tortuga de lava'' con forma de isla de Jeju", "facilities": "Cafetería, baños y una pequeña tienda en la entrada; el sistema de tubos de lava de Geomunoreum está cerca", "tip": "Lleve una chaqueta ligera —la cueva se mantiene fresca todo el año— y use calzado con buen agarre para el suelo húmedo e irregular. Los días de cierre, el tour visita en su lugar el tubo de lava de la cueva Micheon de Ilchul Land."}, "convenience": {"restroom": "Disponible en la plaza de entrada", "parking": "Aparcamiento gratuito en la entrada"}, "visitBasics": {"hours": "Todos los días de 09:00 a 18:00 (última entrada alrededor de las 17:10)", "closed": "Primer miércoles de cada mes; cierres periódicos por conservación", "admission": "Adultos ₩4,000 / Jóvenes ₩2,000; gratis para menores de 7 y mayores de 65 años", "walking": "Moderada — alrededor de 1 km de ida y vuelta sobre un suelo de cueva irregular, húmedo y poco iluminado"}, "images": ["/images/tours/ilchulland/chatgpt-image-2026-5-8-07-45-52.webp"], "imageCredits": [{"url": "/images/tours/ilchulland/chatgpt-image-2026-5-8-07-45-52.webp", "source": "atoc-korea"}], "galleryItems": [], "number": 7}], "routeFlowStops": [{"name": "Hallasan 1100", "theme": "Altiplano", "type": "01"}, {"name": "Jusangjeolli", "theme": "Acantilados", "type": "02"}, {"name": "Jeongbang", "theme": "Cascada", "type": "03"}, {"name": "Almuerzo", "theme": "Pausa", "type": "04"}, {"name": "Espectáculo haenyeo", "theme": "Cultura", "type": "05"}, {"name": "Seongsan", "theme": "Cráter", "type": "06"}, {"name": "Manjanggul", "theme": "Tubo de lava", "type": "07"}], "routePhases": [{"phase": "Mañana — Montaña y costa sur", "duration": "1-3", "description": ""}, {"phase": "Mediodía — Almuerzo y cultura haenyeo", "duration": "4-5", "description": ""}, {"phase": "Final — Cráter y tubo de lava", "duration": "6-7", "description": ""}], "routeShapeIntro": {"title": "Cómo fluye el día", "subtitle": "El día transcurre desde el humedal de Hallasan 1100 a través de los acantilados y la cascada de la costa sur, hace una pausa para el almuerzo y luego cruza hacia el este para un espectáculo en vivo de buceo libre de las haenyeo, el ascenso a Seongsan Ilchulbong y el tubo de lava de Manjanggul. Unos 180 km y aproximadamente 5 horas de conducción en total; la recogida suele realizarse entre las 08:30 y las 09:00, con regreso a la ciudad de Jeju alrededor de las 18:00–18:30."}, "whyTourWorks": {"bestFor": ["Viajeros que solo tienen un día en Jeju", "Visitantes primerizos que quieren conocer los sitios UNESCO de la isla", "Viajeros que desean combinar hitos emblemáticos y cultura local", "Viajeros que disfrutan del turismo activo de día completo"], "routeLogicSections": [{"title": "Diseñado para cubrir lo mejor de Jeju en un solo día", "icon": "clock-3", "iconBg": "**bg-amber-50/80** → bg-amber-50/80", "items": [{"label": "Comenzar en el altiplano de Hallasan", "detail": "Empezar en el humedal alpino a 1.100 m sitúa el día frente al núcleo montañoso de Jeju antes de que comience el largo trayecto por la isla."}, {"label": "Mantener la costa sur en el tramo intermedio", "detail": "Jusangjeolli, Jeongbang y el almuerzo mantienen unido el flujo de oeste a este mientras conservan una alta densidad visual a lo largo del mediodía."}, {"label": "Terminar en el este con cráter y cueva", "detail": "La cultura haenyeo, el ascenso a Seongsan y el tubo de lava de Manjanggul convierten el tramo oriental en un sólido final UNESCO, más que en una sucesión de paradas separadas."}]}, {"title": "Por qué este día resulta especialmente completo", "icon": "mountain", "iconBg": "**bg-sky-50/80** → bg-sky-50/80", "items": [{"label": "Tres sitios del Patrimonio Mundial de la UNESCO", "detail": "Hallasan, Seongsan Ilchulbong y Manjanggul forman parte de la inscripción UNESCO de Jeju: la mayor concentración UNESCO posible en un solo día en Jeju."}, {"label": "Una capa cultural viva", "detail": "El espectáculo de buceo libre de las haenyeo añade el Patrimonio Cultural Inmaterial de la UNESCO a un día construido por lo demás sobre formaciones volcánicas."}, {"label": "Máximo valor para el tiempo disponible", "detail": "Montaña, acantilados, cascada, cultura, cráter y cueva en un solo circuito: diseñado para que un único día siga sintiéndose como un viaje completo a Jeju."}]}, {"title": "Cuando las condiciones en el lugar cambian", "icon": "wind", "iconBg": "**bg-slate-50/80** → bg-slate-50/80", "items": [{"label": "El espectáculo de haenyeo depende del clima", "detail": "La demostración de buceo libre al aire libre puede cancelarse con mar agitado; esos días la ruta visita en su lugar el Museo de las Haenyeo."}, {"label": "Manjanggul tiene cierres periódicos", "detail": "Si el tubo de lava está cerrado por conservación o aforo, se utiliza como alternativa el cercano tubo de lava de la cueva Micheon de Ilchul Land."}, {"label": "El horario de regreso puede variar ligeramente", "detail": "El tráfico, la velocidad de marcha del grupo y la afluencia pueden provocar pequeños cambios en el horario de regreso final."}]}], "lessIdealFor": ["Viajeros que prefieren un ritmo lento y relajado", "Viajeros que desean evitar escaleras o caminatas cuesta arriba", "Grupos que viajan con niños muy pequeños", "Huéspedes que se sienten incómodos en pasajes de cueva frescos y poco iluminados"]}, "practicalAccordionItems": [{"id": "pickup", "title": "Horarios de recogida y regreso", "preview": "Salida temprana, regreso a la ciudad de Jeju por la tarde", "content": ["Recogida en la ciudad de Jeju entre las 08:30 y las 09:00", "Regreso a la ciudad de Jeju alrededor de las 18:00–18:30", "La recogida en el aeropuerto se puede coordinar según las circunstancias", "El horario de encuentro definitivo se confirma la noche anterior"]}, {"id": "walking", "title": "Caminata y terreno", "preview": "Ruta activa con escaleras, un ascenso y una cueva", "content": ["El humedal de Hallasan 1100 es un circuito de pasarela fácil de 1 km.", "La cascada Jeongbang incluye escaleras y un sendero rocoso.", "Seongsan Ilchulbong es un ascenso por escaleras si el grupo decide llegar a la cima.", "Manjanggul son unos 1 km de ida y vuelta sobre un suelo de cueva irregular, húmedo y poco iluminado.", "Se recomienda encarecidamente usar calzado cómodo con buen agarre."]}, {"id": "weather", "title": "Ajustes por clima y cierres", "preview": "Generalmente se realiza según lo previsto, con alternativas incorporadas", "content": ["Lluvia ligera: el tour generalmente se realiza con normalidad; la cueva es un refugio natural", "Mar agitado: el espectáculo de buceo libre de las haenyeo puede sustituirse por el Museo de las Haenyeo", "Cierre de Manjanggul: se utiliza en su lugar el cercano tubo de lava de la cueva Micheon de Ilchul Land", "Invierno: el humedal de Hallasan 1100 puede tener nieve o hielo; la ruta puede ajustar los tiempos de estancia"]}, {"id": "flight", "title": "Si llega a Jeju o sale de allí el mismo día", "preview": "Necesita un margen amplio de tiempo por la noche", "content": ["Esta es una ruta de alta densidad que cubre los atractivos emblemáticos de Jeju en un solo día.", "La llegada o salida el mismo día puede funcionar, pero solo si deja suficiente margen por la tarde-noche.", "Se recomienda encarecidamente un vuelo tardío.", "Tenga en cuenta el tráfico, el ritmo de caminata y las condiciones del lugar al evaluar el riesgo de tiempo."]}, {"id": "wear", "title": "Qué ponerse y qué llevar", "preview": "Calzado para caminar, ropa en capas y una chaqueta ligera para la cueva", "content": ["Calzado para caminar con buen agarre", "Ropa en capas para las diferencias de temperatura entre montaña, costa y cueva", "Una chaqueta ligera: Manjanggul se mantiene fresco todo el año", "Sombrero y protección solar", "Botella de agua"]}, {"id": "included", "title": "Qué está incluido / Qué no está incluido", "preview": "Guía, vehículo, recogida y todas las entradas incluidas", "variant": "included", "content": ["Guía profesional de habla inglesa", "Vehículo para grupos pequeños", "Recogida y regreso al hotel en la ciudad de Jeju", "Todas las entradas (Hallasan 1100, Jusangjeolli, Jeongbang, Seongsan, Manjanggul / Museo de las Haenyeo en días alternativos)", "Agua embotellada", "Almuerzo (pago en el lugar)", "Gastos personales de compras", "Propinas para el guía"]}], "practicalWeatherStatic": {"today": {"temp": "—", "label": "Integración de clima en tiempo real"}, "tomorrow": {"temp": "—", "label": "Actualizado diariamente"}, "_seasonalSummary": "A full-island loop covering east, south, and west Jeju in one day. Weather can vary between regions — coastal stops mild year-round, but inland transit can be cooler and windier.", "_seasonalTemperatures": [{"season": "Spring (Mar–May)", "range": "8–22°C", "notes": "Cherry blossoms on east coast in early April; mild driving conditions."}, {"season": "Summer (Jun–Aug)", "range": "22–30°C", "notes": "Hot but humidity moderated by coastal driving. Cheonjiyeon falls at peak flow."}, {"season": "Autumn (Sep–Nov)", "range": "10–24°C", "notes": "Best season — clearest visibility across all stops, comfortable walking temps."}, {"season": "Winter (Dec–Feb)", "range": "3–10°C", "notes": "Wind chill significant at Seongsan rim and Jusangjeolli cliffs. Fewer crowds at all stops."}]}, "seasonalVariations": [{"season": "Primavera", "description": "El aire de la montaña se siente especialmente fresco, y la visibilidad en toda la isla suele ser más clara y luminosa."}, {"season": "Verano", "description": "Los días son más largos, y los colores de la costa tienden a sentirse más vívidos e intensos."}, {"season": "Otoño", "description": "Los cielos despejados suelen hacer que la ruta por toda la isla se sienta especialmente satisfactoria de principio a fin."}, {"season": "Invierno", "description": "El aire se vuelve más nítido y claro, y el contraste entre la montaña y el mar se hace aún más intenso."}], "bookingTrustItems": [{"icon": "clock-3", "title": "Lo mejor de Jeju, en un solo día", "description": "Tres sitios UNESCO más cultura haenyeo", "iconBg": "bg-emerald-50/80", "body": "Operador local con licencia que diseña este circuito para viajeros que disponen de un solo día y quieren los hitos más reconocibles de Jeju —un altiplano de Hallasan, acantilados columnares, una cascada que cae al océano, un espectáculo en vivo de haenyeo, el cono de tobas de Seongsan y el tubo de lava de Manjanggul— en un único recorrido."}, {"icon": "mountain", "title": "Enfocado en hitos emblemáticos", "description": "Del altiplano de Hallasan a un tubo de lava UNESCO", "iconBg": "bg-sky-50/80", "body": "Especialistas en rutas que operan habitualmente el circuito por toda la isla: la secuencia de paradas minimiza los rodeos y ajusta las paradas de la costa sur y de las haenyeo a la marea, la luz y los horarios de las demostraciones."}, {"icon": "users", "title": "Operación en grupo reducido", "description": "Con mayor capacidad de adaptarse a cierres y condiciones del lugar", "iconBg": "bg-amber-50/80", "body": "El formato en grupo reducido mantiene el día flexible: el guía puede cambiar el espectáculo de haenyeo por el museo, o Manjanggul por el tubo de lava de Ilchul Land, sin romper la ruta."}], "bookingSupportSteps": [{"timing": "Tras la reserva", "title": "Confirmación inmediata", "detail": "Se envía una confirmación de reserva con un resumen del recorrido."}, {"timing": "12 horas antes", "title": "Recordatorio previo a la salida", "detail": "Se comparten con antelación notas meteorológicas y orientaciones sobre ajustes de ruta."}, {"timing": "La noche anterior", "title": "Aviso final de recogida", "detail": "Recibes tu hora exacta de recogida y los datos de contacto."}, {"timing": "La mañana de la salida", "title": "Nota de ruta del día", "detail": "Se comparten brevemente las últimas novedades in situ antes de la salida."}, {"timing": "Durante el recorrido", "title": "Orientación parada a parada", "detail": "Se comparte información clave en cada parada según sea necesario."}, {"timing": "Después del recorrido", "title": "Asistencia posterior al recorrido > **Note:** Items **7**, **10**, and **13** (`bg-emerald-50/80`, `bg-sky-50/80`, `bg-amber-50/80`) are CSS utility class names and have been left untranslated as they are technical identifiers, not natural language.", "detail": "El soporte de seguimiento y las recomendaciones adicionales están disponibles si es necesario."}], "staticQuestions": [{"id": "one-day", "question": "Si solo tengo un día en Jeju, ¿es esta la ruta adecuada?", "answer": "Sí. Esta ruta está diseñada para cubrir los hitos principales de Jeju —tres sitios UNESCO, cultura haenyeo, acantilados y una cascada— en un solo día, a un ritmo más rápido que un tour de un día estándar."}, {"id": "unesco", "question": "¿Cuáles son las paradas que son sitios UNESCO?", "answer": "Tres: el humedal de Hallasan 1100 (parte del área del Patrimonio Mundial de Hallasan), Seongsan Ilchulbong y el tubo de lava de Manjanggul, todos dentro de la inscripción de Jeju ''Isla Volcánica y Tubos de Lava''. El espectáculo de haenyeo es además Patrimonio Cultural Inmaterial de la UNESCO."}, {"id": "haenyeo", "question": "¿Qué pasa si se cancela el espectáculo de haenyeo?", "answer": "La demostración de buceo libre al aire libre depende de las condiciones del mar. Si se cancela, la ruta visita el cercano Museo de las Haenyeo, que cuenta la misma historia de las mujeres buceadoras en interiores."}, {"id": "manjanggul", "question": "¿Manjanggul está siempre abierto?", "answer": "Manjanggul cierra periódicamente por conservación y aforo. Cuando está cerrado, el tour visita en su lugar la cercana cueva Micheon de Ilchul Land, otro tubo de lava del mismo sistema volcánico."}, {"id": "tiring", "question": "¿Resultará cansada esta ruta?", "answer": "Es más activa que un tour de un día típico en grupo reducido: la ruta cubre la mayor parte de la isla e incluye el ascenso a Seongsan, las escaleras de Jeongbang y la caminata por la cueva de Manjanggul."}, {"id": "flight", "question": "¿Puedo unirme si llego a Jeju o salgo de allí el mismo día?", "answer": "Es posible, pero solo con un margen amplio por la tarde-noche. Si el horario de su vuelo es ajustado, esta ruta no es recomendable."}, {"id": "manjanggul-last", "question": "¿Por qué Manjanggul está programado al final?", "answer": "Se encuentra de camino de regreso hacia la ciudad de Jeju y funciona como un final UNESCO fresco y resguardado tras un largo día de formaciones al aire libre."}], "guestReviews": [], "reviewsSummary": {"averageRating": 0, "totalReviews": 0, "ratingDistribution": [{"stars": 5, "count": 0, "percentage": 0}, {"stars": 4, "count": 0, "percentage": 0}, {"stars": 3, 